-- Schema for Domain: audience | Business:  | Version: v2_ecm
-- Generated on: 2026-06-23 01:12:02

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `vibe_media_broadcasting_v1`.`audience` COMMENT 'Owns audience measurement, ratings intelligence, and viewership data — Nielsen ratings, GRP/TRP/HUT/PUT metrics, sweeps period data, reach and frequency reporting, demographic segmentation, and engagement metrics. Integrates with Nielsen Media Research Platform and Adobe Experience Platform to provide the authoritative audience dataset for ad sales, programming decisions, and regulatory reporting.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`nielsen_rating` (
    `nielsen_rating_id` BIGINT COMMENT 'Unique surrogate identifier for each Nielsen audience measurement record in the Silver layer. Primary key for the nielsen_rating data product.',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Nielsen ratings must track originating broadcast facility for FCC regulatory compliance reporting, signal quality correlation analysis, and transmission verification. Broadcast facilities are the lice',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Ratings measurement tied to specific licensed broadcast facilities for regulatory reporting. Nielsen data aggregated by license for FCC public interest demonstration and license renewal applications.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: Nielsen ratings measure campaign delivery performance for billing reconciliation, makegood determination, and audience guarantee compliance. Essential for post-campaign analysis and advertiser reporti',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or network on which the program aired and for which this rating was measured.',
    `compliance_content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Nielsen ratings measurement requires content rating context for demographic targeting compliance (COPPA childrens programming restrictions) and advertiser suitability verification. Essential for regu',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart (time segment of the broadcast day) during which the program aired, such as Prime Time, Late Night, or Early Morning. Daypart is a core dimension for ad sales and programming decisions.',
    `market_coverage_id` BIGINT COMMENT 'Reference to the geographic market (DMA or national) for which this rating measurement applies. Supports both national and local market measurement.',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each Nielsen rating uses a specific measurement methodology (PPM, diary, set-top box). The measurement_type string should be replaced with FK to measurement_methodology for MRC accreditation tracking ',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Nielsen ratings require certified measurement technicians to validate panel compliance, equipment calibration, and sweeps period data accuracy for MRC accreditation audits. Technician assignment track',
    `audience_nielsen_program_code_id` BIGINT COMMENT 'Nielsen Media Research Platforms proprietary alphanumeric code uniquely identifying the program title within the Nielsen measurement system. Used as the business identifier for cross-referencing ratings data with Nielsen deliverables.',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Nielsen ratings directly inform ad sales opportunity valuation and pricing negotiations. Sales teams reference specific program ratings when building proposals and justifying CPM/CPRP rates to adverti',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Nielsen ratings for syndicated content must track which distribution partners broadcast generated the rating for syndication performance reporting and partner revenue reconciliation. Essential for pa',
    `political_ad_record_id` BIGINT COMMENT 'Foreign key linking to compliance.political_ad_record. Business justification: Nielsen ratings used for political advertising rate calculations (lowest unit charge) and public file disclosure. FCC requires ratings documentation for political ad pricing verification and equal tim',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level Nielsen ratings are the primary measurement unit for episodic television. Required for per-episode performance analysis, makegood calculations, and syndication valuation. Standard indust',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Nielsen ratings reports measure performance of specific production projects/series. Essential for greenlight decisions, talent negotiations, and advertiser delivery verification. Standard operational ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Ratings directly measure profit center performance for network/channel business units. Quarterly profit center reviews and segment reporting for investors require tying advertising revenue and audienc',
    `rating_status_id` BIGINT COMMENT 'Lifecycle status of this Nielsen rating record indicating whether the data is preliminary (fast nationals), final, or has been revised. Ad sales and programming decisions must distinguish preliminary from final ratings. Preliminary ratings are typically released within 24 hours; final ratings follow within days.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Nielsen ratings data included in FCC filings for license renewal and public interest demonstration. Ratings evidence programming service to community and support renewal applications.',
    `source_system_record_code_id` BIGINT COMMENT 'The native record identifier assigned by the Nielsen Media Research Platform for this rating record. Preserved in the Silver layer for data lineage, reconciliation, and re-ingestion traceability back to the authoritative source system.',
    `sox_control_id` BIGINT COMMENT 'Foreign key linking to compliance.sox_control. Business justification: Nielsen ratings data used in revenue recognition controls for SOX compliance (advertising revenue). Ratings support revenue assertions; links measurement data to financial reporting controls.',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Nielsen ratings during sweeps periods (Feb, May, July, Nov) are the currency for annual upfront negotiations and local ad sales. The sweeps_period_flag indicates relevance, but the specific sweeps per',
    `title_id` BIGINT COMMENT 'Reference to the program entity for which this audience measurement record was captured. Links to the program master data product.',
    `air_date` DATE COMMENT 'The calendar date on which the program episode aired on the specified channel and market. Used as the principal business event date for this measurement record.',
    `air_end_time` TIMESTAMP COMMENT 'The precise date and time at which the program finished airing. Combined with air_start_time to derive program duration for audience measurement calculations.',
    `air_start_time` TIMESTAMP COMMENT 'The precise date and time (including timezone offset) at which the program began airing. Used for exact scheduling alignment and daypart classification.',
    `audience_composition_pct` DECIMAL(18,2) COMMENT 'The percentage of the programs total audience represented by the primary target demographic (typically A18-49). Indicates how well the program indexes against its target audience and is used in ad sales proposals and programming strategy.',
    `average_audience` DECIMAL(18,2) COMMENT 'The average number of persons or households tuned to the program during an average minute of the telecast. Expressed in thousands (000s). AA is the primary audience volume metric used in GRP and CPM calculations for ad sales.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `cume_audience` DECIMAL(18,2) COMMENT 'The unduplicated number of different persons or households that tuned to the program for at least one minute across all airings within a defined period. Expressed in thousands (000s). Cume measures total reach and is critical for frequency management in ad campaign planning.',
    `demo_a18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Adults aged 18-49 in the measured universe who were tuned to this program. A18-49 is the most commercially valuable and widely traded demographic in US television advertising, serving as the primary currency for primetime ad sales.',
    `demo_a25_54_rating` DECIMAL(18,2) COMMENT 'The percentage of Adults aged 25-54 in the measured universe who were tuned to this program. A25-54 is a key secondary demographic used in news programming, cable networks, and certain advertiser categories.',
    `demo_k2_11_rating` DECIMAL(18,2) COMMENT 'The percentage of Children aged 2-11 in the measured universe who were tuned to this program. K2-11 is the primary demographic for childrens programming and toy/food advertisers. Subject to COPPA compliance requirements for data handling.',
    `demo_m18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Men aged 18-49 in the measured universe who were tuned to this program. M18-49 is a primary demographic for sports, automotive, and technology advertisers.',
    `demo_w18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Women aged 18-49 in the measured universe who were tuned to this program. W18-49 is a primary demographic for lifestyle, beauty, and household product advertisers.',
    `frequency` DECIMAL(18,2) COMMENT 'The average number of times a unique person or household was exposed to the program within the measurement period. Frequency = GRP / Reach. Used with reach for ad campaign effectiveness analysis and makegoods calculations.',
    `grp` DECIMAL(18,2) COMMENT 'The sum of all ratings delivered by an advertising schedule or program, representing total audience delivery without deduplication. GRP = Reach × Frequency. A fundamental currency metric in ad sales negotiations, upfront deals, and scatter market transactions.',
    `household_rating` DECIMAL(18,2) COMMENT 'The percentage of all television households in the measured universe that were tuned to this program during the measurement period. Expressed as a decimal percentage (e.g., 5.2 = 5.2%). The foundational Nielsen rating metric used for ad pricing and programming evaluation.',
    `household_share` DECIMAL(18,2) COMMENT 'The percentage of households using television (HUT) that were tuned to this program. Share = (Program Audience / HUT) × 100. Measures competitive performance relative to active TV viewers at the same time.',
    `hut_level` DECIMAL(18,2) COMMENT 'The percentage of all television households in the universe that had their television sets in use during the measurement period. HUT is the denominator for household share calculations and a key indicator of overall TV viewing activity.',
    `impressions` DECIMAL(18,2) COMMENT 'The total number of person-level exposures to the program, calculated as average audience multiplied by the number of airings. Expressed in absolute numbers (not thousands). Impressions are the transactional currency for digital and cross-platform ad sales.',
    `ingested_timestamp` TIMESTAMP COMMENT 'The timestamp at which this Nielsen rating record was ingested into the Databricks Lakehouse Silver layer from the Nielsen Media Research Platform. Used for data freshness monitoring, SLA tracking, and audit trail.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent update to this rating record in the Silver layer, reflecting revisions from Nielsen (e.g., preliminary to final, or restated ratings). Supports change tracking and downstream consumer notification.',
    `nielsen_report_date` DATE COMMENT 'The date on which Nielsen Media Research officially published or delivered this rating record to the broadcaster. Distinguishes the measurement air date from the data delivery date, which is critical for tracking preliminary vs. final rating release cycles.',
    `nielsen_report_week` STRING COMMENT 'The ISO 8601 week identifier (e.g., 2024-W23) of the Nielsen measurement week in which this rating was reported. Nielsen measurement weeks run Monday through Sunday. Used for weekly ratings aggregation and trend analysis.. Valid values are `^d{4}-W(0[1-9]|[1-4][0-9]|5[0-3])$`',
    `put_level` DECIMAL(18,2) COMMENT 'The percentage of all persons in the measured universe who were watching television during the measurement period. PUT is the denominator for persons share calculations and complements HUT for demographic audience analysis.',
    `reach` DECIMAL(18,2) COMMENT 'The unduplicated number of unique persons or households exposed to the program at least once within the measurement period. Expressed in thousands (000s). Reach is a core metric for ad campaign planning and audience delivery reporting.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this rating was measured during a Nielsen Sweeps period (February, May, July, November intensive measurement periods). Sweeps ratings carry elevated importance for affiliate compensation, ad rate setting, and programming strategy.',
    `time_spent_viewing_min` DECIMAL(18,2) COMMENT 'The average number of minutes that viewers in the measured audience spent watching the program. A key engagement metric used in programming decisions and content performance analysis. Expressed in minutes.',
    `total_audience` DECIMAL(18,2) COMMENT 'The total number of persons or households that tuned to the program for at least six consecutive minutes. Expressed in thousands (000s). TA provides a broader reach measure than AA and is used for program promotion and scheduling decisions.',
    `trp` DECIMAL(18,2) COMMENT 'Rating points delivered specifically to a defined target demographic audience (e.g., Adults 18-49). TRP = (Target Audience Impressions / Target Universe) × 100. Used by advertisers to evaluate efficiency of reaching their specific target demographic.',
    `universe_estimate_hh` DECIMAL(18,2) COMMENT 'The total estimated number of television households in the measured market or national universe used as the denominator for household rating calculations. Expressed in thousands (000s). Nielsen updates universe estimates annually based on census data.',
    `universe_estimate_persons` DECIMAL(18,2) COMMENT 'The total estimated number of persons in the measured market or national universe used as the denominator for persons rating calculations. Expressed in thousands (000s). Segmented by demographic group for TRP calculations.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_nielsen_rating PRIMARY KEY(`nielsen_rating_id`)
) COMMENT 'Authoritative audience measurement record capturing program-level ratings data including household rating, share, HUT/PUT levels, GRP, TRP, average audience (AA), total audience (TA), cume audience, and demographic breakdowns (A18-49, A25-54, W18-49, M18-49, K2-11, etc.) for a specific program airing on a specific channel, market, and daypart. Sourced from Nielsen Media Research Platform. Includes universe estimates used as denominators for percentage calculations. The SSOT for all ratings intelligence consumed by ad sales, programming, and regulatory reporting. Supports both national and local market measurement. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`demographic_segment` (
    `demographic_segment_id` BIGINT COMMENT 'Unique surrogate identifier for each demographic segment record in the audience measurement reference master. Primary key for the demographic_segment product. [_canonical_skip_reason: Role classified as REFERENCE_LOOKUP — this is a reference master for standardized audience demographic classification cells; per-role minimums are exempt, but MASTER_RESOURCE minimums are applied given the entity carries rich descriptive and lifecycle attributes beyond a simple code list.]',
    `adobe_segment_code_id` BIGINT COMMENT 'The corresponding segment identifier in Adobe Experience Platform (AEP) for digital audience activation. Enables cross-system reconciliation between Nielsen linear audience measurement and AEP digital audience profiles for cross-platform campaign targeting and DAI (Dynamic Ad Insertion) on OTT/streaming platforms.',
    `ethnicity_classification_id` BIGINT COMMENT 'Standardized ethnicity classification label for ethnicity-based demographic segments (e.g., Hispanic/Latino, African American, Asian American, Non-Hispanic White). Populated only for ethnicity segment types. Aligned with Nielsen multicultural audience measurement standards and used in targeted content programming and ad sales. [ENUM-REF-CANDIDATE: hispanic_latino|african_american|asian_american|non_hispanic_white|native_american|multiracial|other — promote to reference product]',
    `iab_audience_code_id` BIGINT COMMENT 'The IAB Audience Taxonomy 2.0 standardized code corresponding to this demographic segment. Enables cross-platform audience targeting alignment between linear broadcast, OTT/AVOD/SVOD digital campaigns, and programmatic advertising systems. Used in Salesforce Media Cloud ad proposals and Adobe Experience Platform segment mapping.',
    `nielsen_segment_code_id` BIGINT COMMENT 'The native segment identifier assigned by the Nielsen Media Research Platform for this demographic cell. Used for direct API integration with Nielsen ratings data feeds, ensuring accurate mapping of audience measurement data to internal segment definitions.',
    `segment_code_id` BIGINT COMMENT 'Externally-known alphanumeric code uniquely identifying the demographic segment, aligned with Nielsen and IAB standard cell codes (e.g., A18-49, W25-54, M18-34, K2-11, P2+). Used as the business-facing identifier in ad sales proposals, ratings reports, and audience targeting systems.',
    `segment_status_id` BIGINT COMMENT 'Current lifecycle state of the demographic segment definition. Active segments are available for audience targeting, ad sales proposals, and ratings reporting. Deprecated segments are retained for historical continuity but no longer used in new campaigns or programming decisions.',
    `segment_type_id` BIGINT COMMENT 'Classification of the segment by its primary defining dimension. Distinguishes age/gender cells (Nielsen standard cells such as A18-49) from psychographic profiles, income quintiles, ethnicity classifications, behavioral clusters, and household composition segments. Drives which measurement methodology and data source applies.',
    `age_range_max` STRING COMMENT 'Upper bound (inclusive) of the age range defining this demographic cell, expressed in years. For example, 49 for the A18-49 cell. A null value indicates an open-ended upper bound (e.g., Adults 55+). Null for non-age-based segments.',
    `age_range_min` STRING COMMENT 'Lower bound (inclusive) of the age range defining this demographic cell, expressed in years. For example, 18 for the A18-49 cell. Null for non-age-based segments such as psychographic or income quintile segments.',
    `cpm_index` DECIMAL(18,2) COMMENT 'Relative CPM (Cost Per Mille) pricing index for this demographic segment compared to the baseline segment (index = 100). Premium segments such as A18-49 or W25-54 carry higher indices reflecting advertiser demand. Used in Salesforce Media Cloud ad sales proposals and upfront/scatter market pricing negotiations. Confidential commercial pricing data.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this demographic segment record was first created in the Silver Layer data product. Provides audit trail for data governance and lineage tracking in the Databricks Lakehouse environment.',
    `daypart_relevance` STRING COMMENT 'Comma-separated list of broadcast dayparts (e.g., Prime Time, Late Fringe, Daytime) for which this demographic segment has primary relevance in programming and ad sales strategy. Informs Ericsson MediaFirst scheduling decisions and Wide Orbit daypart-based ad pod targeting. Null if the segment applies across all dayparts.',
    `effective_from` DATE COMMENT 'The date from which this demographic segment definition is valid and available for use in audience measurement, ad sales targeting, and programming decisions. Supports temporal versioning of segment definitions as Nielsen and IAB standards evolve.',
    `effective_until` DATE COMMENT 'The date after which this demographic segment definition is no longer valid for new audience measurement or ad targeting use. Null for currently active segments with no planned expiry. Enables historical ratings data to reference the correct segment definition vintage.',
    `gdpr_special_category` BOOLEAN COMMENT 'Indicates whether this demographic segment is based on GDPR Article 9 special category data (e.g., ethnicity, health status). When true, enhanced consent and data processing controls are required for EU audience data associated with this segment. Relevant for pan-European distribution platforms and Ofcom-regulated services.',
    `gender_qualifier` STRING COMMENT 'Gender dimension of the demographic cell. All denotes combined-gender segments (e.g., Adults 18-49, Persons 2+). Aligns with Nielsen standard gender breakdowns used in GRP/TRP calculations and ad sales targeting.. Valid values are `all|male|female|non_binary`',
    `geographic_scope` STRING COMMENT 'The geographic level at which this demographic segment definition is applied. National segments are used for network-level ratings and upfront sales; DMA (Designated Market Area) segments apply to local market measurement; local applies to individual station markets; international for global distribution platforms.. Valid values are `national|dma|local|international`',
    `grp_weight_factor` DECIMAL(18,2) COMMENT 'Weighting factor applied to this demographic segment when calculating Gross Rating Points (GRP) and Target Rating Points (TRP) in audience measurement reports. Reflects the relative population size and measurement panel representation of the segment. Sourced from the Nielsen Media Research Platform and used in Wide Orbit ad scheduling and campaign delivery calculations.',
    `household_composition` STRING COMMENT 'Classification of household structure for household-based demographic segments. Used in HUT (Homes Using Television) and PUT (Persons Using Television) audience measurement reporting and in family-oriented programming and advertising targeting strategies.. Valid values are `single|couple_no_children|family_with_children|empty_nester|multigenerational`',
    `income_quintile` STRING COMMENT 'Household income quintile ranking (1=lowest 20%, 5=highest 20%) for income-based demographic segments. Populated only for income quintile segment types. Used in premium CPM pricing tiers and upfront ad sales targeting for high-value audience packages.',
    `is_children_segment` BOOLEAN COMMENT 'Indicates whether this demographic segment includes individuals under 13 years of age (e.g., K2-11, K2-5). Triggers COPPA compliance controls on data collection, ad targeting restrictions, and content rating enforcement. Critical for regulatory compliance in digital and broadcast advertising.',
    `is_key_demo` BOOLEAN COMMENT 'Flags whether this segment is designated as a key demographic (key demo) for the organizations primary ad sales and programming strategy. Key demos (typically A18-49, W25-54) command premium CPM rates and are the primary currency in upfront and scatter market negotiations.',
    `is_nielsen_standard_cell` BOOLEAN COMMENT 'Indicates whether this demographic segment corresponds to an official Nielsen standard demographic cell (e.g., A18-49, W25-54). True for Nielsen-defined cells used in GRP/TRP/HUT/PUT ratings calculations; False for custom or proprietary segments defined internally or via Adobe Experience Platform.',
    `measurement_methodology` STRING COMMENT 'The audience measurement methodology used to quantify this demographic segment. Panel-based measurement uses Nielsen People Meter panels; census-based uses set-top box or streaming data; hybrid combines both; modeled uses statistical projection. Determines data quality, confidence intervals, and applicability for regulatory reporting.. Valid values are `panel|census|hybrid|modeled`',
    `nielsen_cell_label` STRING COMMENT 'The exact Nielsen Media Research standard cell label for this demographic segment (e.g., A18-49, W25-54, M18-34, K2-11, P2+). Used as the authoritative cross-reference when ingesting Nielsen ratings data and reconciling audience measurement reports from the Nielsen Media Research Platform.',
    `platform_applicability` STRING COMMENT 'Indicates the distribution platforms for which this demographic segment definition is applicable. Linear segments apply to traditional broadcast/cable measurement; digital applies to OTT/streaming (SVOD, AVOD, FAST); cross-platform spans both; all applies universally. Drives segment availability in Wide Orbit (linear) vs. Adobe Experience Platform (digital) targeting.. Valid values are `linear|digital|cross_platform|all`',
    `psychographic_profile` STRING COMMENT 'Descriptive label for psychographic segment classification (e.g., Early Adopters, Value Seekers, Sports Enthusiasts, News Junkies). Populated only for psychographic segment types. Derived from Adobe Experience Platform audience profiling and used in premium ad sales targeting and programming strategy.',
    `reach_potential_pct` DECIMAL(18,2) COMMENT 'Estimated maximum reach potential expressed as a percentage of the segment universe achievable across the organizations full distribution footprint. Used in media planning to set realistic reach targets for ad campaigns and programming strategies. Sourced from Nielsen reach and frequency models.',
    `regulatory_restriction_flag` BOOLEAN COMMENT 'Indicates whether this demographic segment is subject to regulatory restrictions on data collection, targeting, or advertising. True for segments including minors (COPPA), sensitive demographic categories under GDPR Article 9, or segments subject to FCC advertising restrictions. Triggers compliance workflow in Adobe Experience Platform and Wide Orbit.',
    `segment_description` STRING COMMENT 'Full narrative description of the demographic segments defining characteristics, measurement criteria, and intended use cases. Provides context for business users in ad sales, programming, and analytics teams on how to correctly apply and interpret the segment in audience measurement and targeting workflows.',
    `segment_name` STRING COMMENT 'Human-readable label for the demographic segment (e.g., Adults 18-49, Women 25-54, Men 18-34, Kids 2-11). Used in reporting dashboards, ad sales presentations, and EPG audience targeting configurations.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `sweeps_priority` BOOLEAN COMMENT 'Indicates whether this demographic segment is a priority measurement target during Nielsen sweeps periods (February, May, July, November). Priority segments receive enhanced panel measurement and are the primary basis for affiliate compensation and ad rate card negotiations during sweeps.',
    `universe_estimate` BIGINT COMMENT 'Total estimated population count (universe) for this demographic segment in the measurement geography, as defined by Nielsen. Used as the denominator in ratings calculations (rating = audience / universe × 100). Updated periodically from Nielsen universe estimates and used in GRP, TRP, reach, and frequency reporting.',
    `universe_estimate_year` STRING COMMENT 'The calendar year for which the universe estimate is valid. Nielsen updates universe estimates annually; this field identifies the vintage of the estimate to ensure correct ratings calculations and year-over-year audience trend analysis.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this demographic segment record was most recently modified. Used for incremental data pipeline processing, change data capture, and audit compliance in the Databricks Lakehouse Silver Layer.',
    CONSTRAINT pk_demographic_segment PRIMARY KEY(`demographic_segment_id`)
) COMMENT 'Reference master for standardized audience demographic segments used across Nielsen ratings, ad sales, and programming decisions. Defines age/gender cells (A18-49, W25-54, M18-34, K2-11, etc.), psychographic segments, income quintiles, and ethnicity classifications aligned with Nielsen and IAB standards. Used as the authoritative classification for all audience targeting and measurement reporting. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`sweeps_period` (
    `sweeps_period_id` BIGINT COMMENT 'Unique surrogate identifier for each Nielsen sweeps measurement period record in the Media Broadcasting audience data product.',
    `calendar_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_calendar. Business justification: Sweeps periods drive compliance calendar deadlines for ratings-based regulatory filings. FCC public file updates and license renewal exhibits tied to sweeps completion dates.',
    `data_release_status_id` BIGINT COMMENT 'Indicates the current release state of Nielsen audience data for this sweeps period. unreleased = data not yet available; preliminary = fast affiliate estimates published; final = confirmed ratings delivered; revised_final = post-delivery corrections applied.',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each sweeps period uses a specific measurement methodology (PPM, diary, or hybrid). The measurement_methodology string should be replaced with FK to measurement_methodology master for consistency and ',
    `nielsen_sweep_code_id` BIGINT COMMENT 'The externally-assigned Nielsen Media Research Platform identifier for this sweeps period (e.g., SWEEP-2024-NOV). Used to cross-reference records with Nielsen source data and reconcile audience measurement deliverables.',
    `period_status_id` BIGINT COMMENT 'Current lifecycle state of the sweeps period record. scheduled = future period confirmed by Nielsen; active = measurement currently in progress; completed = measurement concluded and data delivered; cancelled = period cancelled (rare); revised = dates or scope amended post-publication.',
    `audience_sample_size` STRING COMMENT 'Total number of Nielsen panel respondents (diary participants or PPM device carriers) included in the measurement sample for this sweeps period. Larger sample sizes yield higher statistical confidence in ratings estimates.',
    `blackout_markets` STRING COMMENT 'Comma-separated list of DMA market codes where geographic broadcast blackout restrictions apply during this sweeps period. Blackout markets are excluded from certain ratings calculations and ad delivery reporting per FCC and contractual requirements.',
    `ccpa_applicable` BOOLEAN COMMENT 'Indicates whether CCPA viewer data privacy requirements apply to the measurement data collected during this sweeps period (e.g., for California DMA markets in scope). Governs opt-out rights and data sale restrictions for audience panel data.',
    `coppa_applicable` BOOLEAN COMMENT 'Indicates whether COPPA restrictions apply to audience data collected during this sweeps period, specifically for childrens programming dayparts or platforms. Governs collection and use of audience data for viewers under 13.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `daypart_coverage` STRING COMMENT 'Indicates which dayparts (time segments of the broadcast day) are included in the sweeps measurement scope. all_dayparts covers the full broadcast day; other values indicate restricted measurement windows. Daypart coverage affects which ad inventory can be rated and guaranteed.. Valid values are `all_dayparts|primetime_only|primetime_and_late_news|custom`',
    `demographic_breakdowns` STRING COMMENT 'Comma-separated list of demographic segments for which Nielsen will provide audience measurement data during this sweeps period (e.g., A18-49,A25-54,W18-34,M18-49,HH). Determines which target audience guarantees can be supported for ad sales.',
    `diary_return_rate_pct` DECIMAL(18,2) COMMENT 'For diary-methodology sweeps periods, the percentage of distributed Nielsen viewing diaries that were returned by respondents. A key data quality indicator; low return rates may trigger Nielsen data quality warnings or adjustments.',
    `dma_list_version` STRING COMMENT 'Version identifier of the Nielsen DMA market list applied during this sweeps period (e.g., DMA-2024-v1). Nielsen periodically revises DMA boundaries; this field ensures correct market mapping for historical comparisons.',
    `duration_days` STRING COMMENT 'Total number of calendar days in the sweeps measurement window (end_date minus start_date inclusive). Typically 28 days for standard Nielsen sweeps periods. Used in pacing and audience guarantee calculations.',
    `end_date` DATE COMMENT 'The official last day of the Nielsen sweeps measurement window as defined by Nielsen Media Research. Audience data collection and ratings calculations conclude on this date.',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether GDPR audience data privacy requirements apply to the measurement data collected during this sweeps period (e.g., for EU markets included in scope). Governs data retention, consent, and anonymization obligations for audience panel data.',
    `grp_guarantee_applicable` BOOLEAN COMMENT 'Indicates whether Gross Rating Point (GRP) audience guarantees negotiated during the upfront or scatter market apply to advertising campaigns running within this sweeps period. True = GRP guarantees in effect; False = no guarantees applicable.',
    `hut_measurement_included` BOOLEAN COMMENT 'Indicates whether Homes Using Television (HUT) level data is captured and reported as part of this sweeps period measurement. HUT data is used to calculate share and contextualize ratings within total available audience.',
    `is_special_programming_flag` BOOLEAN COMMENT 'Indicates whether special programming (e.g., season premieres, finales, major sporting events, stunting) was scheduled during this sweeps period that may inflate or distort ratings relative to non-sweeps periods. True = special programming present; False = standard schedule.',
    `makegood_window_end_date` DATE COMMENT 'The last date by which makegoods (compensatory ad spots issued when audience guarantees are not met) must be aired following this sweeps period. Defined in advertiser contracts and governed by Wide Orbit traffic system scheduling.',
    `market_count` STRING COMMENT 'Total number of Designated Market Areas (DMAs) included in this sweeps measurement period. Used to assess geographic coverage and local affiliate reporting obligations.',
    `market_scope` STRING COMMENT 'Indicates whether this sweeps period covers national audience measurement, local market (DMA) measurement, or both. Determines which ad sales rate cards and audience guarantees apply.. Valid values are `national|local|both`',
    `nielsen_contract_ref` STRING COMMENT 'Reference number of the Nielsen Media Research contract or service agreement under which this sweeps period measurement is conducted. Used for billing reconciliation and SLA enforcement with Nielsen.',
    `ppm_compliance_rate_pct` DECIMAL(18,2) COMMENT 'For PPM-methodology sweeps periods, the percentage of PPM panel members who met Nielsens minimum daily wear-time compliance threshold. Low compliance rates may affect the statistical validity of ratings data.',
    `preliminary_ratings_date` DATE COMMENT 'The date on which Nielsen delivers preliminary (fast affiliate) ratings estimates for this sweeps period. Preliminary data is used for early ad sales negotiations before final ratings are confirmed.',
    `put_measurement_included` BOOLEAN COMMENT 'Indicates whether Persons Using Television (PUT) level data is captured and reported as part of this sweeps period measurement. PUT data enables person-level demographic audience analysis beyond household-level HUT data.',
    `ratings_delivery_date` DATE COMMENT 'The date on which Nielsen is contractually obligated to deliver final audience ratings data for this sweeps period to the broadcaster. Drives downstream ad sales billing, makegoods calculations, and audience guarantee reconciliation.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this sweeps period record was first created in the Media Broadcasting Databricks Silver layer data product. Supports audit trail and data lineage tracking.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this sweeps period record was most recently modified in the Media Broadcasting Databricks Silver layer data product. Used for change tracking, SLA monitoring, and downstream refresh orchestration.',
    `regulatory_reporting_required` BOOLEAN COMMENT 'Indicates whether audience measurement data from this sweeps period must be submitted to a regulatory body (e.g., FCC, Ofcom) as part of broadcast licensing compliance or public interest reporting obligations.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `source_last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which the source system (Nielsen Media Research Platform) last updated the record for this sweeps period. Used for incremental data ingestion and change detection in the Databricks Silver layer pipeline.',
    `start_date` DATE COMMENT 'The official first day of the Nielsen sweeps measurement window as defined by Nielsen Media Research. Audience data collection and ratings calculations begin on this date.',
    `stunting_description` STRING COMMENT 'Free-text description of any programming stunts or special events scheduled during this sweeps period (e.g., Season finale of flagship drama, Super Bowl lead-out programming). Populated only when is_special_programming_flag is True.',
    `sweep_month` STRING COMMENT 'The calendar month in which the sweeps measurement period falls. Nielsen conducts four sweeps periods annually: February, May, July, and November. Drives programming strategy and ad rate negotiations.. Valid values are `February|May|July|November`',
    `sweep_name` STRING COMMENT 'Human-readable label for the sweeps period (e.g., November 2024 Sweeps, February 2025 Sweeps). Used in reports, ad sales proposals, and programming strategy documents.',
    `sweep_year` STRING COMMENT 'The four-digit calendar year in which the sweeps measurement period occurs (e.g., 2024). Used to uniquely identify the period in combination with sweep_month.',
    `trp_guarantee_applicable` BOOLEAN COMMENT 'Indicates whether Target Rating Point (TRP) audience guarantees for specific demographic targets apply to advertising campaigns running within this sweeps period. True = TRP guarantees in effect; False = no TRP guarantees applicable.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `upfront_rate_card_applicable` BOOLEAN COMMENT 'Indicates whether advertising rates negotiated during the upfront sales event apply to inventory sold within this sweeps period. True = upfront rate cards govern pricing; False = scatter market rates apply.',
    CONSTRAINT pk_sweeps_period PRIMARY KEY(`sweeps_period_id`)
) COMMENT 'Master record for each Nielsen sweeps measurement period (February, May, July, November) defining the official start and end dates, measurement methodology (diary vs. PPM), markets in scope, and special programming flags. Sweeps periods drive programming strategy, ad rate negotiations, and audience guarantee calculations. Sourced from Nielsen Media Research Platform. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`panel` (
    `panel_id` BIGINT COMMENT 'Unique surrogate identifier for the audience measurement panel record in the lakehouse. Primary key for the audience_panel entity.',
    `adobe_segment_code_id` BIGINT COMMENT 'Identifier linking this audience panel definition to a corresponding audience segment or profile group in Adobe Experience Platform (AEP). Enables cross-platform audience activation by mapping Nielsen panel demographics to digital audience segments for personalization and targeted ad delivery.',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Panel recruitment and weighting tied to licensed station coverage areas. Nielsen panels structured around broadcast license service contours to ensure representative sampling for ratings currency.',
    `audience_country_code_id` BIGINT COMMENT 'ISO 3166-1 alpha-3 three-letter country code indicating the primary country of coverage for this panel (e.g., USA, GBR, AUS). Required for international panels and regulatory reporting to Ofcom and the European Audiovisual Observatory.',
    `data_collection_method_id` BIGINT COMMENT 'Technical mechanism used to collect viewing data from panel members. Electronic meters (people meters) require active button-pressing; set-top-box (STB) and smart TV ACR (Automatic Content Recognition) are passive; diary is self-reported. Determines the granularity and reliability of minute-by-minute audience data.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Audience panels require dedicated panel managers responsible for recruitment, retention, weighting methodology compliance, and MRC accreditation maintenance. Manager assignment critical for universe e',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Audience panels are defined for specific DMAs/markets. The dma_code and dma_name are redundant with market_coverage master data. Normalizing ensures consistency with market definitions used across nie',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each panel uses a specific measurement methodology (PPM, diary, set-top box). The measurement_provider string should be replaced with FK to measurement_methodology for consistency. Panel-specific impl',
    `mrc_accreditation_status_id` BIGINT COMMENT 'Current accreditation status granted by the Media Rating Council (MRC) for this panel. MRC accreditation is the industry standard for currency-grade audience measurement. Accredited panels are required for guaranteed ad buys and upfront sales commitments. Non-accredited panels cannot be used as primary currency.',
    `nielsen_panel_code_id` BIGINT COMMENT 'Nielsens proprietary internal identifier for this panel as maintained in the Nielsen Media Research Platform. Used for direct API integration, data feed reconciliation, and cross-referencing Nielsen ratings reports. Distinct from the internal audience_panel_id surrogate key.',
    `panel_code_id` BIGINT COMMENT 'Externally-known alphanumeric code assigned by the measurement provider (e.g., Nielsen) to uniquely identify this panel within their system. Used for cross-system reconciliation with the Nielsen Media Research Platform.',
    `panel_status_id` BIGINT COMMENT 'Current lifecycle state of the audience panel. Active panels are used for currency-grade audience projections. Suspended panels are temporarily halted due to quality or compliance issues. Retired panels are decommissioned and replaced by newer vintages.',
    `panel_type_id` BIGINT COMMENT 'Classification of the audience measurement methodology used by this panel. National People Meter (NPM) and Local People Meter (LPM) are electronic metered panels; Portable People Meter (PPM) captures out-of-home exposure; Diary is self-reported; Return Path Data (RPD) is set-top-box passback data; Hybrid combines multiple methods.',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Audience panels are geographically recruited and must link to the primary broadcast facility serving that DMA for local market measurement, signal quality validation, and MRC accreditation audits. Rol',
    `universe_estimate_type_id` BIGINT COMMENT 'Specifies whether the universe_estimate represents total households, total persons, or TV households (HUT-eligible). TV households are the standard denominator for HUT (Homes Using Television) calculations in broadcast ratings.',
    `cooperation_rate` DECIMAL(18,2) COMMENT 'Percentage of recruited panel households or individuals who are actively and consistently providing usable measurement data. A declining cooperation rate is an early indicator of panel quality degradation and may trigger MRC review. Expressed as a decimal (e.g., 0.8500 = 85%).',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience panel record was first created in the lakehouse Silver layer. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for data lineage, audit trails, and compliance with SOX financial reporting controls that require traceability of audience data used in revenue recognition.',
    `demographic_composition` STRING COMMENT 'Narrative or structured description of the demographic breakdowns captured by this panel (e.g., Age 2+, Adults 18-49, Adults 25-54, Persons 2-17, Households by income quintile). Defines which demographic cuts are available for TRP (Target Rating Point) calculations and demographic audience guarantees in ad sales.',
    `effective_end_date` DATE COMMENT 'Date on which this panel was retired or superseded by a newer panel vintage. Null for currently active panels. Used to scope historical ratings queries to the correct panel vintage and to manage panel transitions during sweeps periods.',
    `effective_start_date` DATE COMMENT 'Date on which this panel became the active currency measurement source for audience projections. Marks the beginning of the period for which this panels data is used in ratings reports, ad sales guarantees, and GRP/TRP delivery calculations.',
    `geographic_scope` STRING COMMENT 'Breadth of geographic coverage represented by this panel. National panels project to the total US population; DMA (Designated Market Area) panels project to a specific local television market; International panels cover non-US territories.. Valid values are `national|dma|local_market|regional|international`',
    `measurement_currency_flag` BOOLEAN COMMENT 'Indicates whether this panel is designated as the official currency measurement source for audience guarantees in advertising transactions. True = this panels data is used as the contractual basis for GRP/TRP delivery and makegood calculations in upfront and scatter market deals. False = supplemental or research-only panel.',
    `min_reportable_rating` DECIMAL(18,2) COMMENT 'The lowest audience rating value (expressed as a decimal fraction of the universe) that this panel can reliably report without exceeding acceptable statistical error thresholds. Ratings below this threshold are suppressed or flagged as unreliable. Typically expressed as a percentage (e.g., 0.0010 = 0.1%). Governed by MRC minimum cell size requirements.',
    `mrc_accreditation_date` DATE COMMENT 'Date on which the MRC most recently granted or renewed accreditation for this panel. Used to track accreditation currency and schedule renewal audits. Panels must maintain continuous accreditation to support upfront and scatter market ad sales guarantees.',
    `mrc_accreditation_expiry_date` DATE COMMENT 'Date on which the current MRC accreditation for this panel expires and must be renewed. Expiry triggers a mandatory re-audit process. Ad sales teams must be notified of impending expiry to manage risk on guaranteed audience delivery commitments.',
    `panel_name` STRING COMMENT 'Human-readable name of the audience measurement panel (e.g., Nielsen National People Meter 2024, Nielsen Local People Meter — New York DMA). Used in reporting, dashboards, and ad sales presentations.',
    `notes` STRING COMMENT 'Free-text field for capturing operational notes, known data quality issues, methodology changes, or special considerations associated with this panel (e.g., Sample boosted in Q3 2023 for Hispanic demographic, Methodology change effective Jan 2024 — includes streaming). Used by audience analytics and ad sales teams.',
    `out_of_home_measurement_flag` BOOLEAN COMMENT 'Indicates whether this panel captures out-of-home (OOH) viewing, such as viewing in bars, hotels, airports, and other public venues. OOH measurement is captured via Portable People Meter (PPM) technology. OOH-inclusive panels produce higher total audience estimates than in-home-only panels.',
    `recruitment_methodology` STRING COMMENT 'Statistical sampling approach used to recruit panel members. Probability-based sampling (address-based or random-digit-dial) is required for MRC-accredited currency panels. Opt-in panels are used for supplemental or proprietary measurement. Affects the projectability and accreditation status of the panel.. Valid values are `probability_sample|address_based|random_digit_dial|opt_in_panel|hybrid`',
    `refresh_frequency` STRING COMMENT 'Cadence at which panel membership is rotated or refreshed to prevent panel conditioning effects and maintain demographic representativeness. Annual and biennial refreshes are standard for people meter panels; continuous recruitment is used for large-scale return path data panels.. Valid values are `annual|biennial|continuous|on_demand`',
    `reporting_granularity` STRING COMMENT 'Finest time interval at which this panel can produce reliable audience estimates. Minute-by-minute granularity is available from electronic people meter panels and supports DAI (Dynamic Ad Insertion) optimization. Quarter-hour is standard for diary panels. Determines compatibility with EPG-based program-level ratings reporting.. Valid values are `minute|quarter_hour|program|daypart|daily`',
    `sampling_error_pct` DECIMAL(18,2) COMMENT 'Estimated margin of error (as a percentage) for audience projections derived from this panel at a 95% confidence interval. Smaller panels have higher sampling error. Used by ad sales teams to communicate measurement uncertainty to advertisers and to set makegood thresholds for audience delivery shortfalls.',
    `size_households` STRING COMMENT 'Total number of sample households actively participating in this panel at any given time. Drives the statistical reliability and margin of error of projected audience estimates. A larger panel size yields lower sampling error for low-rated programs.',
    `size_individuals` STRING COMMENT 'Total number of individual persons (panelists) actively measured within this panel. Distinct from household count because multiple individuals per household are measured for demographic breakdowns used in Target Rating Point (TRP) calculations.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `streaming_measurement_flag` BOOLEAN COMMENT 'Indicates whether this panel captures streaming and OTT (Over-The-Top) viewing in addition to linear broadcast. Streaming-enabled panels support cross-platform audience measurement combining linear TV, SVOD, AVOD, and FAST channel viewing for total audience reporting.',
    `sweeps_eligible_flag` BOOLEAN COMMENT 'Indicates whether this panel is used during Nielsen Sweeps periods (February, May, July, November) for local market ratings measurement. Sweeps data drives local ad rates and program scheduling decisions. Only MRC-accredited panels with sufficient local market sample sizes are sweeps-eligible.',
    `universe_estimate` BIGINT COMMENT 'Total projected population size (in persons or households) that this panel is designed to represent. The universe estimate is the denominator used to convert raw panel viewing counts into ratings percentages (e.g., HUT, PUT, Share). Updated periodically based on census data.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience panel record was most recently modified in the lakehouse Silver layer. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used to detect stale panel configurations and trigger downstream recalculation of audience projections dependent on this panel.',
    `vintage_year` STRING COMMENT 'Calendar year in which this panel sample was designed and recruited. Panels are periodically refreshed to maintain demographic representativeness as the population changes. Vintage year is used to track panel age and schedule mandatory refreshes per MRC accreditation requirements.',
    `weighting_factor` DECIMAL(18,2) COMMENT 'Numeric multiplier applied to this panels raw viewing data to project sample observations to the total universe estimate. A weighting factor greater than 1.0 indicates the panel under-represents a demographic segment relative to the population. Used in GRP and TRP calculations.',
    `weighting_methodology` STRING COMMENT 'Description of the statistical weighting approach applied to panel data to correct for demographic imbalances and non-response bias (e.g., Iterative Proportional Fitting / Raking, Post-stratification weighting by age/sex/race/income). Critical for ensuring projected audience estimates are representative of the total population.',
    CONSTRAINT pk_panel PRIMARY KEY(`panel_id`)
) COMMENT 'Master record representing a Nielsen or proprietary audience measurement panel — a statistically representative sample of households or individuals used to project viewership to the total population. Captures panel type (Nielsen National People Meter, Nielsen Local People Meter, PPM, Diary, Return Path Data), panel size, geographic coverage (national or DMA-specific), demographic composition, panel vintage, recruitment methodology, weighting factors, and MRC accreditation status. Foundation for all projected audience estimates and the basis for measurement credibility. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`viewership_record` (
    `viewership_record_id` BIGINT COMMENT 'Unique surrogate identifier for each granular viewership record in the Silver Layer lakehouse. Primary key for this entity.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: Viewership records are attributed to campaigns for cross-platform measurement, addressable advertising delivery verification, and DAI performance tracking. Essential for programmatic ad insertion and ',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or streaming platform channel on which the content was delivered. Used for channel-level ratings aggregation, share calculations, and carriage fee reporting.',
    `closed_caption_record_id` BIGINT COMMENT 'Foreign key linking to compliance.closed_caption_record. Business justification: Viewership sessions must track caption availability for accessibility compliance auditing. Supports FCC complaint investigation and CVAA compliance reporting by correlating viewing with caption delive',
    `compliance_consent_record_id` BIGINT COMMENT 'Foreign key linking to compliance.consent_record. Business justification: Viewership data collection requires active consent record for GDPR/CCPA compliance. Direct regulatory link ensuring data processing legality and supporting privacy request fulfillment (access, deletio',
    `compliance_content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Viewership tracking must enforce age-appropriate content delivery based on rating system for parental controls and COPPA compliance. Core requirement for subscriber protection and regulatory adherence',
    `incident_id` BIGINT COMMENT 'Foreign key linking to compliance.incident. Business justification: Viewership data breaches or unauthorized access trigger privacy compliance incidents. GDPR/CCPA breach notification requirements mandate linking affected records to incident documentation.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Viewership data attributes content consumption to producing cost centers for ROI analysis. Content performance reports by cost center drive budget allocation and greenlight decisions for programming d',
    `audience_country_code_id` BIGINT COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the viewers geographic location at time of viewing. Used for international rights windowing compliance, GDPR/CCPA jurisdictional determination, and Ofcom/FCC regulatory reporting.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Viewership records undergo quality audits for billing reconciliation, ratings certification, and advertiser makegood disputes. Auditor assignment tracked for compliance trails, client dispute resoluti',
    `delivery_type_id` BIGINT COMMENT 'Classification of how the content was delivered to the viewer. Linear = traditional scheduled broadcast; VOD = on-demand; SVOD = subscription on-demand; AVOD = ad-supported on-demand; TVOD = transactional/pay-per-view; FAST = Free Ad-Supported Streaming Television; Simulcast = simultaneous multi-platform broadcast. Critical for rights windowing compliance and revenue attribution. [ENUM-REF-CANDIDATE: linear|vod|svod|avod|tvod|fast|simulcast — 7 candidates stripped; promote to reference product]',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Viewership records are classified by demographic segment for aggregation into Nielsen ratings. The demographic_age_band and demographic_gender should be replaced with FK to demographic_segment for con',
    `audience_device_type_id` BIGINT COMMENT 'Category of device used to consume the content. Used for device-level audience segmentation, ad targeting eligibility, and platform-specific reach reporting. [ENUM-REF-CANDIDATE: tv|set_top_box|mobile|tablet|desktop|smart_tv|streaming_stick|gaming_console|dvr — promote to reference product]',
    `household_id` BIGINT COMMENT 'Hashed/anonymized identifier representing the household unit from which the viewing event originated, derived from set-top box or ACR data. Pseudonymized per GDPR Article 25 and CCPA Section 1798.100 to prevent direct re-identification. Used for Nielsen household-level ratings aggregation and HUT (Homes Using Television) calculations.',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Viewership records are tracked by DMA for local market measurement. The geographic_dma_code should be replaced with FK to market_coverage for consistency with nielsen_rating and other measurement prod',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Viewership records require originating facility tracking for CDN routing optimization, regional blackout enforcement, local ad insertion decisioning, and FCC local content compliance. Role prefix dist',
    `audience_platform_type_id` BIGINT COMMENT 'The distribution platform category through which the content was delivered. Used for multi-platform audience aggregation, MVPD/vMVPD carriage reporting, and OTT vs. linear audience segmentation. [ENUM-REF-CANDIDATE: broadcast|cable|satellite|ott|mvpd|vmvpd|web|mobile|podcast|social — promote to reference product]',
    `playback_session_id` BIGINT COMMENT 'External business identifier for the viewing session as assigned by the source system (Adobe Experience Platform, set-top box telemetry, or streaming platform). Used to correlate records across ingestion pipelines and deduplicate events from multiple sources.',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level viewership tracking is standard for streaming platforms. Required for completion rate analysis, binge-watching pattern detection, and dynamic ad insertion targeting. Core operational lin',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the specific scheduled airing or playout event from the Electronic Program Guide (EPG) that the viewer tuned into. Links to the program schedule managed in Ericsson MediaFirst. Null for on-demand (VOD/SVOD) sessions.',
    `subscriber_id` BIGINT COMMENT 'Reference to the authenticated subscriber account from Zuora subscription billing, populated for SVOD and authenticated AVOD sessions. Null for anonymous linear broadcast or unauthenticated OTT viewing.',
    `title_id` BIGINT COMMENT 'Reference to the content asset being viewed, linking to the content master catalog. Enables join to content metadata including title, genre, production details, and rights windows.',
    `viewer_profile_id` BIGINT COMMENT 'Hashed/anonymized identifier representing an individual viewer within a household, derived from Adobe Experience Platform profile resolution or subscriber login. Pseudonymized per GDPR and CCPA. Used for PUT (Persons Using Television) and individual-level demographic analytics.',
    `viewing_status_id` BIGINT COMMENT 'Current lifecycle status of the viewing session record. completed = viewer watched to end or tune-out cleanly; in_progress = session still active at ingestion time; abandoned = viewer left before 10% completion; interrupted = session ended due to technical failure; error = telemetry data quality issue flagged.',
    `acr_source` STRING COMMENT 'The data collection methodology or source system that generated this viewership record. ACR = Automatic Content Recognition from smart TV; set_top_box = return-path data from cable/satellite STB; streaming_telemetry = OTT platform event stream via Adobe Experience Platform; panel = Nielsen People Meter panel; return_path = MVPD return-path data.. Valid values are `set_top_box|acr|streaming_telemetry|panel|return_path`',
    `ad_break_count` STRING COMMENT 'Number of ad breaks (ad pods) encountered by the viewer during this viewing session. Used for DAI (Dynamic Ad Insertion) reconciliation, Wide Orbit affidavit verification, and advertiser delivery reporting.',
    `ads_viewed_count` STRING COMMENT 'Total number of individual advertisement spots viewed (not skipped) by the viewer during this session. Used for AVOD monetization reporting, CPM impression counting, and advertiser campaign delivery verification against Wide Orbit schedules.',
    `audience_share` DECIMAL(18,2) COMMENT 'The percentage of HUT (Homes Using Television) or PUT (Persons Using Television) tuned to this channel/program at the time of viewing, as reported by Nielsen. Share differs from rating in that it measures the proportion of active viewers rather than the total universe. Used for competitive programming analysis.',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a geographic blackout restriction was applied to this viewing session, preventing delivery of specific content in the viewers DMA or region per rights agreements. Used for blackout compliance auditing and retransmission consent reporting.',
    `broadcast_date` DATE COMMENT 'The calendar date (yyyy-MM-dd) of the broadcast or streaming session, in the local broadcast timezone. Used as the primary date dimension for daily ratings aggregation, sweeps period attribution, and Nielsen overnight ratings reporting.',
    `cdn_edge_node` STRING COMMENT 'Identifier of the Akamai CDN edge node or point-of-presence (PoP) that served the streaming content for this session. Used for CDN performance analysis, SLA compliance monitoring, and geographic delivery optimization.',
    `completion_rate` DECIMAL(18,2) COMMENT 'Proportion of the content asset viewed during this session, expressed as a decimal between 0.0000 and 1.0000 (e.g., 0.7500 = 75% viewed). Sourced directly from platform telemetry; not derived within this product. Used for engagement scoring, programming decisions, and advertiser reporting.',
    `content_duration_seconds` STRING COMMENT 'Total runtime in seconds of the full content asset or scheduled airing being viewed. Used as the denominator for completion rate calculations and to determine whether a full viewing occurred.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this viewership record was ingested into the Silver Layer. Used for data lineage tracking, quality auditing, and source-system reconciliation.. Valid values are `adobe_experience_platform|nielsen_platform|akamai_cdn|set_top_box|acr_provider`',
    `daypart` STRING COMMENT 'The broadcast daypart time segment during which the tune-in occurred, as defined by industry standard time blocks. Daypart is a fundamental dimension for advertising sales (CPM pricing, GRP/TRP calculations), programming strategy, and Nielsen ratings reporting. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|prime_access|primetime|late_news|late_fringe|overnight — promote to reference product]',
    `drm_protected` BOOLEAN COMMENT 'Indicates whether the content stream was delivered with DRM (Digital Rights Management) encryption active during this session. Used for rights compliance auditing, anti-piracy reporting to MPA, and content protection SLA verification.',
    `duration_viewed_seconds` STRING COMMENT 'Total number of seconds the viewer actively watched the content during this session, as reported by the source telemetry system. Accounts for pauses and buffering exclusions per platform telemetry rules. Used for TSR (Time Spent Reading/Viewing) calculations and completion rate derivation.',
    `ingestion_timestamp` TIMESTAMP COMMENT 'The date and time when this viewership record was first loaded into the Databricks Silver Layer lakehouse. Used for data freshness monitoring, SLA compliance, and audit trail purposes. Distinct from tune_in_timestamp (business event time).',
    `is_authenticated` BOOLEAN COMMENT 'Indicates whether the viewer was authenticated (logged in) at the time of viewing. Authenticated sessions enable individual-level audience measurement and subscriber-linked analytics. Unauthenticated sessions rely on household or device-level inference.',
    `is_sweeps_period` BOOLEAN COMMENT 'Flag indicating whether this viewership record falls within a Nielsen sweeps measurement period (February, May, July, November). Sweeps data is used for setting advertising rates and programming decisions. Critical for isolating sweeps vs. non-sweeps audience behavior.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this viewership record was last modified in the Silver Layer, for example due to late-arriving data corrections, Nielsen restatement, or session completion updates. Used for incremental processing and audit trail.',
    `nielsen_program_rating` DECIMAL(18,2) COMMENT 'The Nielsen audience rating score associated with the program airing for this viewership record, representing the percentage of the total TV households or persons in the universe tuned to the program. Sourced from Nielsen Media Research Platform integration. Used for GRP/TRP calculations and ad rate setting.',
    `playback_position_seconds` STRING COMMENT 'The content offset position in seconds at which the viewer stopped watching (tune-out position within the asset). For linear broadcast, this reflects the offset from the scheduled start of the program. Used for resume-point analytics and mid-roll ad delivery attribution.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `stream_quality` STRING COMMENT 'The video quality level at which the content was delivered during this session, as reported by the ABR (Adaptive Bitrate Streaming) player or CDN telemetry from Akamai. Used for quality-of-experience reporting, CDN SLA compliance, and premium content delivery analytics.. Valid values are `4k_uhd|hd_1080|hd_720|sd|audio_only`',
    `tune_in_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the viewer began watching the content or tuned to the channel. This is the principal business event timestamp for the viewership record. Used for daypart analysis, time-spent calculations, and sweeps period attribution.',
    `tune_out_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the viewer stopped watching, changed channel, or the session ended. Used in conjunction with tune_in_timestamp to calculate duration_viewed_seconds.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `viewing_status` STRING COMMENT '',
    CONSTRAINT pk_viewership_record PRIMARY KEY(`viewership_record_id`)
) COMMENT 'Granular transactional record of audience viewing activity for a specific content airing or stream session, capturing tuning start/end timestamps, channel or platform, device type, household or individual viewer identifier (anonymized/hashed per GDPR/CCPA), duration viewed, and completion rate. Aggregated from set-top box data, ACR (Automatic Content Recognition), and streaming platform telemetry via Adobe Experience Platform integration. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`reach_frequency_report` (
    `reach_frequency_report_id` BIGINT COMMENT 'Unique surrogate identifier for each reach and frequency report record in the Silver Layer lakehouse. Primary key for this transactional entity.',
    `advertiser_id` BIGINT COMMENT 'Foreign key linking to sales.advertiser. Business justification: Reach/frequency reports are generated for specific advertisers to show campaign performance across their portfolio, including cross-campaign reach, frequency distribution, and GRP/TRP delivery. Essent',
    `campaign_id` BIGINT COMMENT 'Reference to the advertising campaign for which this reach and frequency report was produced. Links to the campaign master record in Salesforce Media Cloud. Used for post-campaign delivery validation and upfront guarantee reconciliation.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to scheduling.channel. Business justification: Reach/frequency reports are generated for specific networks/channels to measure campaign delivery by channel. Direct channel link enables automated report generation, channel-specific reach analysis, ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Reach/frequency reports measure advertising campaign effectiveness by sales team cost center. Sales commission calculations and territory performance analysis require linking campaign delivery metrics',
    `audience_currency_code_id` BIGINT COMMENT 'The ISO 4217 three-letter currency code for all monetary values in this report (CPM, CPRP). Defaults to USD for domestic US markets. Required for international market reports and multi-currency financial reconciliation under SOX compliance.',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart (time segment of the broadcast day) for which audience measurement was computed. Links to the daypart reference product. Used to segment reach and frequency metrics by time-of-day for programming and ad sales analysis.',
    `demographic_segment_id` BIGINT COMMENT 'Reference to the demographic segment (e.g., Adults 18-49, Women 25-54) against which reach and frequency metrics are measured. Links to the demographic segment reference product sourced from Nielsen Media Research Platform. Central to Target Rating Point (TRP) calculations and ad sales guarantees.',
    `market_coverage_id` BIGINT COMMENT 'Reference to the geographic market (DMA, national, or international market) for which this reach and frequency report applies. Links to the market reference product. Used for blackout compliance, scatter market pricing, and geographic audience analysis.',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Reach/frequency reports are generated using specific Nielsen methodologies. The nielsen_methodology string should be replaced with FK to measurement_methodology for consistency and MRC accreditation t',
    `measurement_type_id` BIGINT COMMENT 'Classifies the type of measurement window for which this report was generated. campaign_flight covers a defined ad campaign run; programming_block covers a scheduled content block; daypart_window covers a standard broadcast daypart; sweeps_period covers an intensive Nielsen ratings measurement period; custom_window covers an ad hoc analysis window.',
    `nielsen_report_code_id` BIGINT COMMENT 'The native report identifier assigned by the Nielsen Media Research Platform for this reach and frequency dataset. Used for source system traceability, data lineage, and reconciliation between the lakehouse Silver Layer and the Nielsen source system.',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Reach/frequency reports are core deliverables in ad sales proposals and post-campaign analysis. Each R&F report is generated for a specific sales opportunity to demonstrate projected or actual campaig',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Reach/frequency reports are often generated for specific distribution or syndication partners to demonstrate audience delivery against contractual obligations. Required for partner performance reporti',
    `audience_platform_type_id` BIGINT COMMENT 'The distribution platform type for which audience reach and frequency is measured. Distinguishes linear (traditional scheduled broadcast), OTT (Over-The-Top streaming), SVOD (Subscription Video On Demand), AVOD (Advertising-Supported Video On Demand), TVOD (Transactional Video On Demand), FAST (Free Ad-Supported Streaming Television), or simulcast (simultaneous multi-platform broadcast). Critical for cross-platform audience deduplication and multi-platform reach reporting. [ENUM-REF-CANDIDATE: linear|OTT|SVOD|AVOD|TVOD|FAST|simulcast — 7 candidates stripped; promote to reference product]',
    `political_ad_record_id` BIGINT COMMENT 'Foreign key linking to compliance.political_ad_record. Business justification: Reach/frequency reports for political campaigns require public inspection file linkage per FCC rules. Demonstrates delivery of reasonable access and documents audience delivery for political advertise',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Reach/frequency reports require certified analysts to validate GRP/TRP calculations, effective reach thresholds, and makegood determinations for advertiser guarantees. Analyst assignment tracked for c',
    `audience_report_status_id` BIGINT COMMENT 'Current lifecycle state of the reach and frequency report. draft indicates in-progress computation; preliminary indicates initial Nielsen delivery pending validation; final indicates validated and approved for client delivery; revised indicates a corrected reissue; superseded indicates replaced by a newer version; archived indicates retired from active use.',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Reach/frequency reports during sweeps periods are used for guarantee verification and makegood calculations. The is_sweeps_period flag indicates relevance, but the specific sweeps period should be ref',
    `audience_share_pct` DECIMAL(18,2) COMMENT 'The percentage of the total viewing audience (persons using television) that was watching the specific network or program during the measurement period. Calculated as the programs audience divided by the total HUT/PUT audience. Used for competitive programming analysis and ad sales positioning.',
    `average_frequency` DECIMAL(18,2) COMMENT 'The average number of times a unique viewer within the target demographic was exposed to the content or campaign during the measurement period. Calculated as total impressions divided by unduplicated reach. Core metric for evaluating campaign saturation and makegoods calculation.',
    `cpm` DECIMAL(18,2) COMMENT 'The cost per one thousand audience impressions for the campaign or programming block, expressed in USD. Used by ad sales for post-campaign delivery validation, scatter market pricing justification, and makegood valuation. Confidential as it reflects negotiated commercial pricing.',
    `cprp` DECIMAL(18,2) COMMENT 'The cost per one rating point delivered against the target demographic segment, expressed in USD. The primary pricing metric for linear TV advertising transactions. Used for upfront guarantee reconciliation, makegood valuation, and scatter market pricing. Confidential as it reflects negotiated commercial pricing.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this reach and frequency report record was first ingested into the Silver Layer lakehouse. Used for data lineage tracking and pipeline monitoring.',
    `delivery_variance_pct` DECIMAL(18,2) COMMENT 'The percentage difference between the guaranteed audience delivery (GRP or TRP) and the actual delivered audience for the campaign flight. A negative value indicates under-delivery triggering makegood obligations; a positive value indicates over-delivery. Used for upfront guarantee reconciliation and scatter market adjustments.',
    `effective_reach_1plus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least one time (1+) during the measurement period. Equivalent to reach_persons; included as an explicit effective reach threshold field for consistency with N+ reporting framework used in post-campaign analysis.',
    `effective_reach_3plus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least three times (3+) during the measurement period. The industry-standard effective reach threshold used to assess whether sufficient frequency was achieved for advertising message recall. Critical for makegoods determination and campaign effectiveness evaluation.',
    `effective_reach_nplus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least N times (as defined by effective_reach_threshold) during the measurement period. Provides a configurable effective reach metric for custom campaign guarantee structures and advanced frequency analysis.',
    `effective_reach_threshold` STRING COMMENT 'The minimum number of exposures (N) used to define effective reach for this specific report. Configurable per campaign or client agreement (e.g., 3 for standard campaigns, 5 for high-frequency campaigns). Determines the N+ threshold applied in effective reach calculations beyond the standard 1+ and 3+ fields.',
    `grp` DECIMAL(18,2) COMMENT 'The sum of all rating points delivered by the campaign or programming block during the measurement period, representing total audience weight without deduplication. Calculated as reach percentage multiplied by average frequency. The primary currency for linear TV advertising transactions and upfront sales guarantees.',
    `hut_rating` DECIMAL(18,2) COMMENT 'The percentage of all television households in the market that had their television sets in use during the measurement period. Sourced from Nielsen Media Research Platform. Used as a contextual benchmark for evaluating audience share and competitive programming performance.',
    `is_makegood_required` BOOLEAN COMMENT 'Indicates whether this reach and frequency report has identified an audience delivery shortfall that requires a makegood (compensatory ad spot) to be issued to the advertiser. Triggers the makegood workflow in Wide Orbit and Salesforce Media Cloud when set to True.',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether the measurement period falls within a Nielsen sweeps period (an intensive ratings measurement period typically occurring in February, May, July, and November). Sweeps data carries elevated importance for programming decisions, ad rate setting, and affiliate compensation calculations.',
    `measurement_period_end_date` DATE COMMENT 'The last date of the measurement window for which reach and frequency metrics are computed. Defines the end boundary of the campaign flight, programming block, or sweeps period being analyzed.',
    `measurement_period_start_date` DATE COMMENT 'The first date of the measurement window for which reach and frequency metrics are computed. Defines the start boundary of the campaign flight, programming block, or sweeps period being analyzed. Used in conjunction with measurement_period_end_date to bound the audience measurement interval.',
    `put_rating` DECIMAL(18,2) COMMENT 'The percentage of all persons in the target demographic who were watching television during the measurement period. Sourced from Nielsen Media Research Platform. Used alongside HUT to assess total available audience and calculate audience share for programming decisions.',
    `reach_pct` DECIMAL(18,2) COMMENT 'The percentage of the target demographic universe reached at least once during the measurement period, calculated as (reach_persons / universe_estimate) × 100. Expressed as a decimal percentage (e.g., 45.2500 = 45.25%). Used by ad sales for post-campaign delivery reporting and scatter market pricing justification.',
    `reach_persons` BIGINT COMMENT 'The unduplicated count of unique persons within the target demographic segment who were exposed to the content or campaign at least once during the measurement period. The primary reach metric sourced from Nielsen Media Research Platform. Used for post-campaign delivery validation and upfront guarantee reconciliation.',
    `report_generated_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when this reach and frequency report was generated and delivered by the Nielsen Media Research Platform. Represents the business event time, distinct from audit timestamps. Used to track Nielsen data delivery SLAs and post-campaign reporting timeliness.',
    `report_number` STRING COMMENT 'Externally-known business identifier for this reach and frequency report, sourced from the Nielsen Media Research Platform. Used by ad sales teams to reference specific post-campaign delivery reports in client communications, makegoods negotiations, and upfront guarantee reconciliation.. Valid values are `^RF-[0-9]{4}-[0-9]{6}$`',
    `report_version` STRING COMMENT 'The version number of this reach and frequency report, incremented each time a revised or corrected report is issued by Nielsen or reprocessed in the lakehouse. Version 1 represents the initial delivery; subsequent versions represent corrections or revisions. Used to ensure ad sales teams are working with the most current data.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `total_impressions` BIGINT COMMENT 'The total number of audience exposures (duplicated) to the content or campaign during the measurement period. Equals reach_persons multiplied by average_frequency. Used as the gross delivery metric for CPM-based advertising transactions and campaign pacing analysis.',
    `trp` DECIMAL(18,2) COMMENT 'The sum of rating points delivered specifically against the target demographic segment during the measurement period. Analogous to GRP but scoped to the defined target audience rather than the total population. Used for targeted advertising guarantee reconciliation and CPRP calculations.',
    `universe_estimate` BIGINT COMMENT 'The total estimated population size (in persons or households) of the target demographic segment in the specified market, as defined by Nielsen. Serves as the denominator for reach percentage calculations and rating point computations. Expressed as an absolute count.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this reach and frequency report record was last modified in the Silver Layer lakehouse. Tracks revisions, status changes, and data corrections.',
    CONSTRAINT pk_reach_frequency_report PRIMARY KEY(`reach_frequency_report_id`)
) COMMENT 'Transactional record capturing computed reach (unduplicated audience count), frequency (average exposures per unique viewer), and effective reach (viewers exposed N+ times) for a defined campaign flight, programming block, or daypart window across a specified demographic segment, market, and measurement period. Sourced from Nielsen Media Research Platform. Used by ad sales for post-campaign delivery validation, makegoods calculation, upfront guarantee reconciliation, and scatter market pricing justification. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`market_coverage` (
    `market_coverage_id` BIGINT COMMENT 'Unique surrogate identifier for the market coverage record representing a Designated Market Area (DMA) or television market geographic unit.',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Market coverage definitions derive from broadcast license service contours and DMA assignments. License technical parameters (power, antenna height) determine market boundaries for audience measuremen',
    `audience_broadcast_standard_id` BIGINT COMMENT 'Digital broadcast transmission standard applicable to this market. ATSC (Advanced Television Systems Committee) is the US standard; DVB (Digital Video Broadcasting) is the European standard; ISDB is the Japanese/Brazilian standard; DTMB is the Chinese standard. Determines technical playout and transmission requirements.',
    `audience_country_code_id` BIGINT COMMENT 'ISO 3166-1 alpha-3 three-letter country code identifying the country in which this market is located (e.g., USA, GBR, CAN). Required for international rights management, windowing decisions, and regulatory jurisdiction determination.',
    `audience_dma_code_id` BIGINT COMMENT 'Nielsen-assigned three-digit numeric code uniquely identifying the Designated Market Area (DMA). This is the externally-known business identifier used across ad sales, ratings reporting, and FCC filings. Sourced from Nielsen Media Research Platform.',
    `fcc_market_code_id` BIGINT COMMENT 'FCC-assigned market identifier used for must-carry and retransmission consent compliance filings. Maps the Nielsen DMA to the FCCs designated market definition for broadcast licensing, spectrum regulation, and MVPD carriage obligations. Required for regulatory reporting under FCC 47 CFR Part 76.',
    `market_status_id` BIGINT COMMENT 'Current lifecycle status of the market coverage record. active indicates the DMA is currently measured and used in audience reporting; inactive indicates it is no longer measured; pending indicates a newly defined market awaiting first measurement; discontinued indicates a market that has been merged or eliminated by Nielsen.',
    `market_type_id` BIGINT COMMENT 'Classification of the market scope. local indicates a single-city DMA; regional indicates a multi-city or multi-state DMA; national indicates a national aggregate market; international indicates a non-US market territory. Used for ad sales segmentation, carriage fee tiers, and programming distribution decisions.',
    `nielsen_source_market_code_id` BIGINT COMMENT 'The native market identifier as assigned and used within the Nielsen Media Research Platform source system. Used for data lineage, reconciliation between the lakehouse silver layer and the Nielsen source system, and audit of universe estimate ingestion.',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Market coverage (DMA) must link to primary licensed broadcast facility for FCC must-carry compliance, retransmission consent negotiations, local content origination requirements, and emergency alert s',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Market coverage areas determine applicable regulatory obligations (must-carry, retransmission consent). DMA and market type drive specific FCC obligations; links market definitions to compliance requi',
    `state_province_code_id` BIGINT COMMENT 'ISO 3166-2 two-letter state or province code of the primary state in which the DMAs principal city is located (e.g., NY, CA, IL). Used for geographic segmentation, blackout rule enforcement, and retransmission consent jurisdiction determination.',
    `blackout_rule_applicable` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout rules apply to this market for sports or syndication exclusivity purposes. True if blackout restrictions can be enforced in this DMA; False otherwise. Used by rights management (Rightsline) and CDN geo-restriction (Akamai) to enforce territorial exclusivity.',
    `cable_penetration_rate` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that subscribe to cable television (MVPD or vMVPD service). Expressed as a decimal (e.g., 0.6234 = 62.34%). Used for carriage fee negotiations, distribution planning, and ad sales reach projections.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `daylight_saving_observed` BOOLEAN COMMENT 'Indicates whether the DMA observes Daylight Saving Time (DST). True if DST is observed; False if not (e.g., markets in Arizona). Affects daypart scheduling, playout timing, and EPG accuracy in broadcast automation systems.',
    `dma_rank` STRING COMMENT 'Nielsen-assigned national rank of the DMA by television household universe size, where rank 1 is the largest market (New York). Used for market prioritization in ad sales, upfront negotiations, and carriage fee calculations. Updated annually by Nielsen.',
    `effective_from_date` DATE COMMENT 'The date from which this market coverage record became effective and the DMA definition was valid. Used for temporal versioning of DMA boundary and universe changes, ensuring historical ratings data is associated with the correct market definition.',
    `effective_to_date` DATE COMMENT 'The date on which this market coverage record ceased to be effective, typically due to a DMA boundary redefinition, market merger, or discontinuation. Null for currently active market definitions. Supports slowly changing dimension (SCD) history tracking.',
    `geographic_boundary_wkt` STRING COMMENT 'Well-Known Text (WKT) representation of the DMAs geographic boundary polygon. Used for spatial analysis, blackout rule enforcement, retransmission consent territory mapping, and OTT/streaming geo-restriction via CDN (Akamai). Conforms to OGC WKT standard.',
    `hispanic_tv_household_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that are Hispanic/Latino, as measured by Nielsen. Expressed as a decimal (e.g., 0.2341 = 23.41%). Used for Spanish-language content distribution decisions, targeted ad sales, and TRP (Target Rating Point) calculations for Hispanic demographic segments.',
    `hut_base_estimate` DECIMAL(18,2) COMMENT 'Nielsen baseline estimate of the percentage of television households in the DMA that are using television during an average primetime daypart. Expressed as a decimal (e.g., 0.5823 = 58.23%). Used as a reference benchmark for HUT-based audience projections and ad sales planning.',
    `market_name` STRING COMMENT 'Official human-readable name of the Designated Market Area (DMA) or television market as defined by Nielsen (e.g., New York, Los Angeles, Chicago). Used in audience reports, ad sales proposals, and regulatory filings.',
    `measurement_frequency` STRING COMMENT 'Frequency at which Nielsen provides audience measurement data for this market. continuous indicates year-round metered measurement (PPM markets); sweeps_only indicates measurement only during sweeps periods (diary markets); quarterly or annual for smaller markets with less frequent measurement cycles.. Valid values are `continuous|sweeps_only|quarterly|annual`',
    `measurement_methodology` STRING COMMENT 'Nielsen measurement methodology applied to this market. PPM (Portable People Meter) is the electronic passive measurement used in large markets; diary is the paper-based recall method used in smaller markets; hybrid indicates a combination of both. Determines the precision and frequency of ratings data available for this market.. Valid values are `PPM|diary|hybrid`',
    `median_household_income` DECIMAL(18,2) COMMENT 'Median annual household income (in USD) for the DMA, sourced from U.S. Census Bureau data as incorporated into Nielsen demographic profiles. Used for audience demographic segmentation, CPM (Cost Per Mille) pricing tiers, and advertiser targeting qualification.',
    `must_carry_applicable` BOOLEAN COMMENT 'Indicates whether FCC must-carry rules apply to broadcast stations in this market, requiring cable operators (MVPDs) to carry local broadcast signals. True if must-carry obligations exist; False otherwise. Critical for retransmission consent negotiations and MVPD carriage compliance.',
    `nielsen_station_index` STRING COMMENT 'Total number of television stations measured by Nielsen within this DMA. Indicates the competitive landscape of the local market and is used in share calculations and ad sales competitive analysis.',
    `ott_penetration_rate` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that access video content via OTT (Over-The-Top) streaming services. Expressed as a decimal. Used for digital distribution planning, SVOD/AVOD audience projections, and DAI (Dynamic Ad Insertion) inventory estimation.',
    `population_universe` BIGINT COMMENT 'Nielsen-estimated total population (persons 2+) residing within the DMA boundary. Used as the denominator for person-based ratings metrics including PUT (Persons Using Television) and TRP (Target Rating Point) calculations. Updated annually in the Nielsen universe estimates release.',
    `primary_language` STRING COMMENT 'ISO 639-1 or ISO 639-2 language code representing the predominant language spoken in the DMA (e.g., en for English, es for Spanish). Used for content localization decisions, Spanish-language network distribution, and audience demographic targeting.. Valid values are `^[a-z]{2,3}$`',
    `principal_city` STRING COMMENT 'Name of the primary city or metropolitan area that anchors and names the DMA (e.g., New York, Los Angeles, Chicago). Used in market identification, ad sales materials, and regulatory filings.',
    `put_base_estimate` DECIMAL(18,2) COMMENT 'Nielsen baseline estimate of the percentage of persons (2+) in the DMA who are using television during an average primetime daypart. Expressed as a decimal (e.g., 0.4612 = 46.12%). Used as a reference benchmark for PUT-based audience projections and TRP calculations.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market coverage record was first created in the Databricks Lakehouse Silver Layer. Used for audit trail, data lineage tracking, and compliance with SOX financial reporting controls that require data provenance.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market coverage record was most recently updated in the Databricks Lakehouse Silver Layer. Used for change detection, incremental processing, and audit trail maintenance.',
    `regulatory_jurisdiction` STRING COMMENT 'Primary broadcast regulatory authority governing this market. FCC for US markets; Ofcom for UK markets; CRTC for Canadian markets; ACMA for Australian markets; other for all other jurisdictions. Determines applicable must-carry, retransmission consent, content standards, and licensing requirements.. Valid values are `FCC|Ofcom|CRTC|ACMA|other`',
    `retransmission_consent_applicable` BOOLEAN COMMENT 'Indicates whether retransmission consent rules apply to broadcast stations in this market, allowing broadcasters to negotiate compensation from MVPDs for carriage of their signals. True if retransmission consent is applicable; False otherwise.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `sweeps_participation` BOOLEAN COMMENT 'Indicates whether this market participates in Nielsen sweeps periods (intensive ratings measurement periods in February, May, July, and November). True if the market is measured during sweeps; False if it is a non-sweeps market. Affects programming scheduling strategy and ad sales pricing.',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the primary time zone of the DMA (e.g., America/New_York, America/Los_Angeles). Critical for daypart scheduling, playout automation in Ericsson MediaFirst, EPG (Electronic Program Guide) alignment, and ad scheduling in Wide Orbit Traffic system.',
    `total_counties` STRING COMMENT 'Total number of counties or county-equivalents included within the DMA boundary. Nielsen defines DMA boundaries at the county level. Used for geographic coverage analysis, must-carry compliance, and retransmission consent territory verification.',
    `tv_household_universe` BIGINT COMMENT 'Nielsen-estimated total number of television households within the DMA boundary. This is the principal quantitative measurement fact for the market and serves as the denominator for all local ratings calculations, GRP/TRP computations, and CPM-based ad pricing. Updated annually in the Nielsen universe estimates release.',
    `universe_effective_date` DATE COMMENT 'The date from which the current Nielsen universe estimates (TV household and population) became effective for this market. Used to track the currency of universe data and ensure ratings calculations use the correct denominator for the applicable measurement period.',
    `universe_estimate_year` STRING COMMENT 'The calendar year for which the Nielsen universe estimates (TV household and population figures) are valid. Nielsen releases updated universe estimates annually, typically effective in the fall. Used to version and audit the universe figures used in ratings calculations.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_market_coverage PRIMARY KEY(`market_coverage_id`)
) COMMENT 'Master record defining a Designated Market Area (DMA) or television market — the geographic unit used for local audience measurement. Captures DMA rank, DMA code, market name, TV household universe estimate, population universe, geographic boundaries, and applicable measurement methodology (PPM vs. diary). Aligns with Nielsen DMA definitions and FCC market designations for must-carry and retransmission consent compliance. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`engagement_event` (
    `engagement_event_id` BIGINT COMMENT 'Unique surrogate identifier for each discrete digital audience engagement action captured on OTT/streaming platforms. Primary key for this product in the Databricks Silver Layer.',
    `campaign_id` BIGINT COMMENT 'Identifier for the advertising campaign associated with this engagement event, populated when the event is triggered within or adjacent to an ad pod. Supports DAI (Dynamic Ad Insertion) attribution and campaign performance measurement.',
    `advertiser_id` BIGINT COMMENT 'Foreign key linking to sales.advertiser. Business justification: Engagement events (clicks, completions, interactions) are attributed to advertisers for performance reporting, creative effectiveness analysis, and cross-campaign optimization. Essential for digital/s',
    `compliance_consent_record_id` BIGINT COMMENT 'Foreign key linking to compliance.consent_record. Business justification: Engagement tracking requires consent validation for data processing legality under GDPR/CCPA. Essential for demonstrating lawful basis for behavioral analytics and targeted advertising.',
    `compliance_content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Engagement analytics require content rating context for COPPA compliance validation and parental control enforcement. Necessary to prevent unauthorized data collection from children viewing age-restri',
    `audience_content_rating_id` BIGINT COMMENT 'Motion Picture Association (MPA) or TV Parental Guidelines content rating of the asset at the time of the engagement event. Used for COPPA compliance (childrens content restrictions), audience demographic validation, and parental control enforcement. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|NC-17|TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA — promote to reference product]',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Digital engagement events are classified by Nielsen demographic segments for audience measurement integration. The nielsen_demo_code should be replaced with FK to demographic_segment for consistency w',
    `audience_device_type_id` BIGINT COMMENT 'Category of the physical device on which the engagement event was generated. Enables device-level audience segmentation and platform distribution analysis. [ENUM-REF-CANDIDATE: smart_tv|mobile|tablet|desktop|set_top_box|gaming_console|other — promote to reference product]',
    `event_status_id` BIGINT COMMENT 'Processing lifecycle status of the engagement event record in the Silver Layer. valid indicates the event passed all quality checks; invalid indicates a data quality failure; duplicate indicates a repeated event suppressed from analytics; quarantined indicates the event is held pending investigation.',
    `audience_event_type_id` BIGINT COMMENT 'Categorical discriminator identifying the specific audience interaction captured: play (content start/resume), pause (playback halted), seek (position jump forward), rewind (position jump backward), share (social distribution action), like (positive sentiment signal), comment (text interaction), complete (full content consumption). Core EVENT_TYPE_OR_CHANNEL field for non-linear audience behaviour analysis. [ENUM-REF-CANDIDATE: play|pause|seek|rewind|share|like|comment|complete — 8 candidates stripped; promote to reference product]',
    `geo_country_code_id` BIGINT COMMENT 'ISO 3166-1 alpha-3 country code of the viewers geographic location at the time of the engagement event, derived from IP geolocation. Used for territorial rights compliance (blackout enforcement, holdback windows), audience reach reporting by geography, and regulatory jurisdiction determination.',
    `geo_region_code_id` BIGINT COMMENT 'ISO 3166-2 subdivision code (state, province, or region) of the viewers location at the time of the engagement event. Used for sub-national blackout enforcement, regional audience measurement, and daypart-adjusted analytics.',
    `audience_isan_code_id` BIGINT COMMENT 'ISAN (International Standard Audiovisual Number) of the content asset associated with this engagement event. Provides a globally unique, persistent identifier for the audiovisual work independent of platform or distribution channel. Supports rights management, royalty calculation, and regulatory reporting.',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Engagement events must track originating broadcast facility for streaming performance analysis, CDN edge optimization, and correlating viewer experience with infrastructure health. Critical for NOC in',
    `ott_platform_id` BIGINT COMMENT 'Identifier for the distribution platform (e.g., OTT app, SVOD service, AVOD channel, FAST channel) on which the engagement event occurred. Enables multi-platform distribution and audience analytics.',
    `playback_session_id` BIGINT COMMENT 'Anonymized identifier for the streaming session during which this engagement event occurred. Links all events within a single continuous viewing session for session-level analytics. Sourced from Adobe Experience Platform session context.',
    `privacy_request_id` BIGINT COMMENT 'Foreign key linking to compliance.privacy_request. Business justification: Privacy requests must locate and process engagement event data for GDPR/CCPA compliance. Links requests to behavioral data for subject access reports and deletion fulfillment.',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level engagement tracking identifies drop-off points, rewatch behavior, and scene-level audience response. Used for post-production feedback, marketing clip selection, and editorial pacing ana',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: Linear engagement events (tune-in, tune-out, ad interactions) must link to schedule slots for slot-level engagement analysis, ad effectiveness measurement, and audience flow tracking. Creates schedule',
    `segment_id` BIGINT COMMENT 'Foreign key linking to audience.audience_segment. Business justification: Engagement events are tagged with custom audience segments for behavioral targeting and activation. The audience_segment_code should be replaced with FK to audience_segment master for consistency and ',
    `source_system_event_code_id` BIGINT COMMENT 'Original event identifier assigned by Adobe Experience Platform at the point of capture, before Silver Layer surrogate key assignment. Used for data lineage tracing, deduplication, and reconciliation between the Silver Layer and the Adobe Experience Platform source system.',
    `subscription_tier_id` BIGINT COMMENT 'Subscription or access tier of the viewer at the time of the engagement event, reflecting the monetisation model under which content was consumed. Sourced from Zuora subscription billing. Used to segment engagement behaviour by revenue tier for ARPU analysis and churn prediction.',
    `title_id` BIGINT COMMENT 'Identifier for the content asset (programme, episode, clip, or ad) against which this engagement event was recorded. Enables content-level audience behaviour analysis for programming decisions.',
    `viewer_profile_id` BIGINT COMMENT 'Anonymized identifier for the audience member or household profile that generated this engagement event. Sourced from Adobe Experience Platform unified profile. Used for audience segmentation and ad targeting without exposing personal identity.',
    `ad_pod_position` STRING COMMENT 'Ordinal position of the advertisement within its ad pod (group of ads in a break) at the time of the engagement event. Populated only when is_ad_event is True. Used to analyse viewer drop-off rates by pod position and optimise ad pod sequencing for revenue assurance.',
    `app_version` STRING COMMENT 'Version string of the OTT/streaming application that captured the engagement event (e.g., 4.2.1). Used to correlate engagement behaviour with app release cycles and identify version-specific anomalies in audience interaction patterns.. Valid values are `^d+.d+.d+$`',
    `bitrate_kbps` STRING COMMENT 'Actual bitrate in kilobits per second of the stream being delivered at the time of the engagement event. Sourced from Akamai CDN performance telemetry. Used alongside stream_quality to assess CDN delivery performance and its impact on audience engagement.',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a geographic broadcast restriction (blackout) was enforced for this viewer at the time of the engagement event (True) or not (False). Supports FCC blackout compliance reporting and rights management audit trails.',
    `buffering_duration_ms` STRING COMMENT 'Total duration of buffering experienced by the viewer immediately preceding or during this engagement event, in milliseconds. Sourced from Adobe Experience Platform quality-of-experience telemetry. Used to correlate buffering events with pause and abandonment engagement actions.',
    `content_duration_ms` BIGINT COMMENT 'Total duration of the content asset in milliseconds at the time of the engagement event. Used in conjunction with content_position_ms to compute completion percentage and engagement depth score. Sourced from Dalet Galaxy asset metadata.',
    `content_genre` STRING COMMENT 'Primary genre classification of the content asset associated with this engagement event (e.g., Drama, News, Sports, Comedy, Documentary). Sourced from Dalet Galaxy asset metadata. Used for genre-level audience behaviour analysis and programming acquisition decisions.',
    `content_position_ms` BIGINT COMMENT 'Playback position within the content asset at the moment the engagement event was triggered, expressed in milliseconds from the start of the content. Core EVENT_PAYLOAD_OR_VALUE for this event log. Enables precise engagement depth analysis, completion rate calculation, and identification of drop-off points.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `data_privacy_consent` STRING COMMENT 'Viewers data privacy consent status at the time of the engagement event, governing permissible use of this record for analytics, personalisation, and ad targeting. Sourced from Adobe Experience Platform consent management. Mandatory for GDPR Article 6 lawful basis determination and CCPA opt-out compliance.. Valid values are `full_consent|analytics_only|no_consent|withdrawn`',
    `daypart` STRING COMMENT 'Broadcast daypart time segment in which the engagement event occurred, classified per industry-standard daypart definitions. Used for audience measurement reporting, ad sales daypart targeting, and programming scheduling decisions. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|prime_access|prime|late_news|late_fringe|overnight — promote to reference product]',
    `device_os` STRING COMMENT 'Operating system of the device that generated the engagement event (e.g., iOS, Android, tvOS, Roku OS, Fire OS, Windows, macOS). Sourced from Adobe Experience Platform device context. Supports technical platform compatibility analysis and audience reach reporting.',
    `drm_scheme` STRING COMMENT 'DRM (Digital Rights Management) protection scheme active on the content stream at the time of the engagement event. Used for rights compliance verification and to ensure content is consumed within licensed windows and territories. Supports Rightsline rights enforcement reporting.. Valid values are `widevine|fairplay|playready|clearkey|none`',
    `engagement_depth_score` DECIMAL(18,2) COMMENT 'Normalised score (0.00–100.00) representing the depth of audience engagement at the time of the event, calculated by Adobe Experience Platform based on playback position relative to content duration, interaction frequency, and event type weighting. Key metric for non-linear audience behaviour analysis and ad targeting propensity modelling.',
    `event_status` STRING COMMENT '',
    `event_timestamp` TIMESTAMP COMMENT 'Precise UTC timestamp recording when the engagement action occurred on the viewers device. Principal EVENT_TIMESTAMP for this event log entity. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for time-series audience behaviour analysis, daypart analytics, and sweeps period reporting.',
    `event_type` STRING COMMENT '',
    `is_ad_event` BOOLEAN COMMENT 'Indicates whether this engagement event occurred during an advertisement (True) or during editorial content (False). Critical for separating content engagement metrics from ad engagement metrics in AVOD and DAI (Dynamic Ad Insertion) analytics.',
    `is_concurrent_stream` BOOLEAN COMMENT 'Indicates whether this engagement event occurred on a stream that was running concurrently with another active stream on the same viewer account (True) or not (False). Used for concurrent stream limit enforcement per subscription terms and HUT (Homes Using Television) measurement.',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether the engagement event occurred during a Nielsen sweeps measurement period (True) or outside of it (False). Sweeps periods are intensive ratings measurement windows critical for ad sales pricing and programming strategy. Enables sweeps vs. non-sweeps audience behaviour comparison.',
    `received_timestamp` TIMESTAMP COMMENT 'UTC timestamp when the engagement event was received and ingested by Adobe Experience Platform. Distinct from event_timestamp (client-side occurrence time). Used to measure event latency, detect clock skew, and support data quality auditing in the Silver Layer pipeline.',
    `referral_source` STRING COMMENT 'Channel or mechanism through which the viewer arrived at the content that triggered this engagement event. Used for audience acquisition attribution, marketing campaign effectiveness analysis, and content discovery optimisation. [ENUM-REF-CANDIDATE: direct|search|social|email|push_notification|in_app|external_link — promote to reference product]',
    `seek_from_position_ms` BIGINT COMMENT 'Playback position in milliseconds from which the viewer initiated a seek or rewind action. Populated only when event_type is seek or rewind. Combined with content_position_ms (seek-to position) to measure skip behaviour and identify content segments that audiences skip or revisit.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `source_system_event_code` STRING COMMENT '',
    `stream_quality` STRING COMMENT 'Adaptive bitrate (ABR) quality tier of the stream at the time of the engagement event, reflecting the HLS or MPEG-DASH rendition being delivered by the CDN. Used to correlate stream quality with engagement behaviour and identify quality-driven churn signals.. Valid values are `4K_UHD|1080p|720p|480p|360p|audio_only`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_engagement_event PRIMARY KEY(`engagement_event_id`)
) COMMENT 'Transactional record capturing a discrete digital audience engagement action on OTT/streaming platforms — including play, pause, seek, rewind, share, like, comment, and content completion events. Sourced from Adobe Experience Platform. Captures event type, content identifier, viewer session identifier (anonymized), platform, device, timestamp, and engagement depth score. Enables non-linear audience behavior analysis for programming and ad targeting. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`guarantee` (
    `guarantee_id` BIGINT COMMENT 'Unique surrogate identifier for the audience delivery guarantee record. Primary key for the audience_guarantee data product in the Silver Layer lakehouse.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Audience guarantees are sold and managed by account executives who negotiate CPRPs, delivery thresholds, makegood terms, and reconciliation with advertisers. AE assignment critical for commission calc',
    `advertiser_id` BIGINT COMMENT 'Reference to the advertiser (party) to whom the audience delivery guarantee is committed. Sourced from Salesforce Media Cloud account records.',
    `audit_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.audit_finding. Business justification: Guarantee delivery shortfalls may trigger audit findings for revenue recognition or contract compliance. SOX audits examine guarantee fulfillment; links findings to specific guarantee contracts.',
    `campaign_id` BIGINT COMMENT 'Reference to the advertising campaign for which this audience delivery guarantee is established. Links to the campaign record in Salesforce Media Cloud or Wide Orbit.',
    `compliance_content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Guarantee fulfillment must account for content rating restrictions affecting deliverable inventory. Advertisers specify rating-appropriate placements; guarantees calculate delivery against compliant i',
    `contract_id` BIGINT COMMENT 'Foreign key linking to talent.talent_contract. Business justification: Upfront sales negotiations frequently tie audience guarantees to specific talent participation (e.g., guaranteed GRPs for episodes featuring marquee talent). Sales teams negotiate rate premiums and de',
    `audience_currency_code_id` BIGINT COMMENT 'ISO 4217 three-letter currency code for the financial values associated with this audience guarantee (e.g., USD, GBP, EUR). Used in CPRP and total guarantee value calculations.',
    `audience_deal_type_id` BIGINT COMMENT 'Classification of the advertising deal under which this guarantee was established. Upfront refers to advance advertising sales events; scatter refers to last-minute ad inventory sales; direct, programmatic, and sponsorship represent other deal structures common in media broadcasting.',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Guarantees target specific standardized demographic segments (e.g., A18-49, W25-54). The target_demographic_code and target_demographic_description are redundant with demographic_segment reference dat',
    `channel_id` BIGINT COMMENT 'Foreign key linking to scheduling.channel. Business justification: Audience guarantees are often negotiated at the network/channel level for upfront deals. Direct channel link enables automated guarantee reconciliation, makegood issuance by channel, and channel-speci',
    `guarantee_network_channel_id` BIGINT COMMENT 'Reference to the television network or channel on which the guaranteed audience delivery is to be achieved. Links to the network/channel master record used in scheduling and playout systems.',
    `guarantee_status_id` BIGINT COMMENT 'Current lifecycle state of the audience guarantee. Draft indicates the guarantee is being negotiated; active indicates it is in-flight; at_risk indicates delivery is trending below threshold; breached indicates the guarantee was not met and makegoods are triggered; fulfilled indicates full delivery was achieved; cancelled indicates the guarantee was voided.',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each guarantee specifies which measurement methodology (Nielsen PPM, diary, set-top box) is used for verification. The measurement_source string should be replaced with a FK to the authoritative measu',
    `nielsen_order_code_id` BIGINT COMMENT 'The external order or tracking identifier assigned by the Nielsen Media Research Platform for the audience measurement order associated with this guarantee. Used to cross-reference Nielsen ratings data and reconciliation reports.',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Audience guarantees are contractual commitments made to specific partners (advertisers, agencies, networks). Tracking the partner receiving the guarantee is essential for makegood fulfillment and cont',
    `audience_platform_type_id` BIGINT COMMENT 'The distribution platform type on which the audience guarantee applies. Linear refers to traditional scheduled broadcasting; OTT (Over-The-Top) covers streaming delivery; SVOD (Subscription Video On Demand), AVOD (Advertising-Supported Video On Demand), TVOD (Transactional Video On Demand), and FAST (Free Ad-Supported Streaming Television) represent specific streaming models; simulcast covers simultaneous multi-platform broadcast. [ENUM-REF-CANDIDATE: linear|OTT|SVOD|AVOD|TVOD|FAST|simulcast — 7 candidates stripped; promote to reference product]',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Upfront audience guarantees specify which production projects/series will deliver promised ratings. Required for makegood reconciliation, advertiser delivery reports, and sales contract fulfillment. C',
    `rating_metric_type_id` BIGINT COMMENT 'Specifies the primary audience measurement metric on which this guarantee is based. GRP (Gross Rating Point) measures total audience exposure; TRP (Target Rating Point) measures exposure within the target demographic; HUT (Homes Using Television) and PUT (Persons Using Television) measure set usage; reach measures unique audience count; frequency measures average exposures per viewer.',
    `audience_reconciliation_status_id` BIGINT COMMENT 'Current status of the reconciliation process comparing guaranteed audience delivery against actual GRP/TRP delivery records. Pending indicates reconciliation has not started; in_progress indicates active comparison; reconciled indicates agreement reached; disputed indicates advertiser has contested the delivery figures; closed indicates the reconciliation cycle is complete.',
    `revenue_stream_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_stream. Business justification: Audience guarantees define revenue recognition terms and makegood liability accounting. ASC 606 compliance requires linking performance obligations (guarantees) to revenue streams for proper recogniti',
    `sales_proposal_id` BIGINT COMMENT 'Foreign key linking to sales.sales_proposal. Business justification: Audience guarantees are negotiated and documented in sales proposals before being formalized in orders. Proposals specify guarantee terms (GRP/TRP thresholds, makegood provisions) that become contract',
    `opportunity_id` BIGINT COMMENT 'The opportunity identifier in Salesforce Media Cloud CRM linked to this audience guarantee. Enables traceability from the sales pipeline through to audience delivery commitment and reconciliation.',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Upfront guarantees specify daypart-level GRP/TRP commitments (e.g., Prime 18-49 rating guarantee). Direct daypart link enables automated delivery tracking, makegood triggering, and daypart-specific re',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Audience guarantees are often tied to specific Nielsen sweeps periods for measurement and makegood calculations. The is_sweeps_period flag indicates relevance, but the specific sweeps period should be',
    `wide_orbit_order_code_id` BIGINT COMMENT 'The sales order identifier in the Wide Orbit Traffic and Billing system associated with this audience guarantee. Used for cross-system reconciliation between audience delivery records and ad scheduling/invoicing.',
    `actual_grp_delivered` DECIMAL(18,2) COMMENT 'The actual total GRP delivered against this guarantee as measured by the designated audience measurement source (e.g., Nielsen). Populated during and after the measurement period through reconciliation with actual delivery records. Used to determine whether the guarantee was met and whether makegoods are required.',
    `actual_trp_delivered` DECIMAL(18,2) COMMENT 'The actual total TRP delivered against this guarantee within the target demographic, as measured by the designated audience measurement source. Populated during reconciliation. Used alongside actual_grp_delivered to assess guarantee fulfillment for demographic-specific commitments.',
    `approved_timestamp` TIMESTAMP COMMENT 'The timestamp when this audience guarantee was formally approved and activated, transitioning from draft to active status. Represents the binding commitment date for revenue recognition and contractual obligation purposes.',
    `cprp` DECIMAL(18,2) COMMENT 'The negotiated cost per rating point (CPRP) for this audience guarantee, expressed in the contract currency. CPRP is the standard pricing metric in broadcast advertising used to calculate the total value of the guarantee and to assess makegood compensation amounts.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this audience guarantee record was first created in the system. Audit trail field used for data lineage, compliance reporting, and Silver Layer ingestion tracking.',
    `delivery_shortfall_grp` DECIMAL(18,2) COMMENT 'The calculated difference between the guaranteed GRP level and the actual GRP delivered (guaranteed_grp minus actual_grp_delivered). A positive value indicates under-delivery and potential makegood obligation. Populated during reconciliation.',
    `effective_end_date` DATE COMMENT 'The calendar date on which the audience delivery guarantee measurement period ends. Nullable for open-ended or rolling guarantees. Defines the close of the window during which GRP/TRP delivery is tracked.',
    `effective_start_date` DATE COMMENT 'The calendar date on which the audience delivery guarantee measurement period begins. Defines the start of the window during which GRP/TRP delivery is tracked against the committed level.',
    `guarantee_number` STRING COMMENT 'Externally-known business identifier for the audience guarantee, used in advertiser-facing documents, contracts, and reconciliation reports. Typically referenced in Wide Orbit sales orders and Salesforce Media Cloud opportunities.. Valid values are `^AG-[0-9]{4}-[0-9]{6}$`',
    `guaranteed_frequency` DECIMAL(18,2) COMMENT 'The minimum average number of times a member of the target audience is exposed to the campaign (frequency) committed to the advertiser. Frequency is the average exposures per viewer. Used alongside reach guarantees for campaigns with specific exposure objectives.',
    `guaranteed_grp` DECIMAL(18,2) COMMENT 'The total Gross Rating Point (GRP) level committed to the advertiser for delivery over the measurement period. GRP is the sum of ratings for all ad spots in the campaign, representing total audience exposure as a percentage of the target universe. This is the contractually obligated delivery level.',
    `guaranteed_reach` DECIMAL(18,2) COMMENT 'The minimum number of unique audience members (reach) committed to the advertiser over the measurement period. Reach is the count of distinct individuals exposed to the campaign at least once. Complements GRP/TRP guarantees for campaigns focused on unique audience coverage.',
    `guaranteed_trp` DECIMAL(18,2) COMMENT 'The total Target Rating Point (TRP) level committed to the advertiser, measured specifically against the defined target demographic segment. TRP is the GRP filtered to the target audience. Used when the guarantee is demographic-specific rather than total audience.',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether the guarantee measurement period falls within a Nielsen sweeps period (intensive ratings measurement period). Sweeps periods (February, May, July, November) carry higher audience measurement scrutiny and may affect guarantee valuation and pricing.',
    `makegood_deadline_date` DATE COMMENT 'The contractual deadline by which makegood spots must be aired to compensate for any audience delivery shortfall. Critical for revenue assurance and advertiser relationship management.',
    `makegood_grp_issued` DECIMAL(18,2) COMMENT 'The total GRP value of makegood (compensatory ad spots) issued to the advertiser to compensate for audience delivery shortfall. Tracked for revenue assurance and advertiser relationship management. Zero if no makegoods were required.',
    `makegood_trigger_condition` STRING COMMENT 'Textual description of the specific conditions under which makegood (compensatory ad spots) obligations are activated. Defines the contractual rules for when and how makegoods must be provided to the advertiser when guaranteed audience delivery is not met. Sourced from the advertising contract terms.',
    `notes` STRING COMMENT 'Free-text field for additional business context, special conditions, or operational notes related to this audience guarantee. May include negotiation history, special advertiser requirements, or reconciliation commentary.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `tolerance_threshold_pct` DECIMAL(18,2) COMMENT 'The acceptable percentage shortfall below the guaranteed GRP/TRP level before a makegood obligation is triggered. For example, a value of 5.00 means delivery must be within 5% of the guaranteed level. Defined in the advertising contract and used in reconciliation against actual delivery records.',
    `total_guarantee_value` DECIMAL(18,2) COMMENT 'The total contracted monetary value of this audience guarantee, calculated as guaranteed GRP/TRP multiplied by CPRP. Represents the revenue at risk if the guarantee is not met and is central to revenue assurance and financial reconciliation.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this audience guarantee record was last modified. Used for change tracking, incremental data processing in the lakehouse Silver Layer, and audit compliance.',
    CONSTRAINT pk_guarantee PRIMARY KEY(`guarantee_id`)
) COMMENT 'Master record of the audience delivery guarantee committed to an advertiser for a specific campaign or upfront deal — specifying the guaranteed GRP/TRP level, target demographic, measurement period, tolerance threshold, and makegood trigger conditions. Links to ad sales contracts and is reconciled against actual GRP delivery records. Central to revenue assurance and advertiser relationship management. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`audience_profile` (
    `audience_profile_id` BIGINT COMMENT 'Unique surrogate identifier for the audience profile record in the Silver Layer lakehouse. Primary key for this entity.',
    `aep_profile_code_id` BIGINT COMMENT 'Unique profile identifier from Adobe Experience Platform (AEP) used to link behavioral engagement data, segment memberships, and journey analytics to this audience profile. Enables personalization and digital engagement enrichment.',
    `audience_country_code_id` BIGINT COMMENT 'ISO 3166-1 alpha-3 country code representing the audience members country of residence. Used for rights windowing, content holdback enforcement, GDPR/CCPA jurisdictional compliance, and international distribution analytics.',
    `device_graph_code_id` BIGINT COMMENT 'Cross-device graph linkage identifier that associates this audience profile with a cluster of known devices (smart TV, mobile, desktop, STB). Sourced from identity resolution providers or Adobe AEP device graph. Enables multi-screen reach and frequency measurement.',
    `gdpr_consent_status_id` BIGINT COMMENT 'Current GDPR consent status for processing this audience members personal data for audience measurement and advertising purposes. granted permits processing; denied or withdrawn restricts processing; not_applicable for non-EU audience members. Drives data processing eligibility.',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Audience profiles are associated with specific DMAs for geographic targeting and measurement. The dma_code should be replaced with FK to market_coverage for consistency with other products. Country_co',
    `panel_id` BIGINT COMMENT 'Pseudonymized identifier assigned by Nielsen Media Research to link this audience profile to a Nielsen panel household or individual. Enables direct integration of Nielsen ratings, GRP/TRP, and demographic data. Null for non-panel profiles.',
    `primary_device_type_id` BIGINT COMMENT 'The primary device type through which this audience member most frequently consumes content, derived from device graph and behavioral data. Used for CDN delivery optimization, ad format targeting, and platform analytics.',
    `audience_profile_status_id` BIGINT COMMENT 'Current lifecycle state of the audience profile. suppressed indicates a privacy opt-out or regulatory hold; pending_consent indicates consent collection is in progress; purged indicates the record has been anonymized per GDPR/CCPA erasure request.',
    `audience_profile_type_id` BIGINT COMMENT 'Classification of the audience profile record: individual (single person identity), household (aggregated household unit), panel_member (Nielsen or equivalent panel participant), or modeled (synthetically constructed from behavioral signals without direct identity linkage).',
    `ad_receptivity_score` DECIMAL(18,2) COMMENT 'Propensity score (0.00–100.00) indicating this audience members likelihood to engage with advertising content, derived from behavioral signals in Adobe AEP and viewing pattern analysis. Used by ad sales teams for premium audience packaging and CPM pricing optimization.',
    `aep_segment_membership` STRING COMMENT 'Comma-delimited list of Adobe Experience Platform (AEP) audience segment IDs to which this profile currently belongs. Segments represent behavioral, demographic, or propensity-based audience groups used for personalization, ad targeting, and journey activation.',
    `avg_session_duration_minutes` DECIMAL(18,2) COMMENT 'Average duration in minutes of a single viewing session for this audience member, derived from set-top box or streaming platform telemetry. Represents Time Spent Viewing (TSV) at the individual level. Used for engagement scoring and content performance analytics.',
    `ccpa_opt_out` BOOLEAN COMMENT 'Indicates whether this California-resident audience member has exercised their CCPA right to opt out of the sale or sharing of their personal information. When TRUE, this profile must be excluded from data sharing with third-party ad networks and data clean rooms.',
    `consent_last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent change to any consent or privacy flag (GDPR consent status, CCPA opt-out, COPPA flag) for this audience profile. Critical for regulatory audit trails demonstrating timely consent management and data processing compliance.',
    `content_affinity_genre` STRING COMMENT 'Top inferred content genre affinity for this audience member (e.g., news, sports, drama, reality, documentary), derived from viewing history and behavioral signals in Adobe AEP. Used for content recommendation, programming decisions, and audience-targeted ad sales. [ENUM-REF-CANDIDATE: news|sports|drama|comedy|reality|documentary|entertainment|kids|lifestyle|sci_fi — promote to reference product]',
    `coppa_protected` BOOLEAN COMMENT 'Indicates whether this audience profile is subject to COPPA (Childrens Online Privacy Protection Act) protections, meaning the inferred or declared age is under 13. When TRUE, ad targeting, data sharing, and behavioral tracking are strictly restricted per COPPA compliance requirements.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience profile record was first created in the Silver Layer lakehouse, either through initial identity resolution, panel enrollment, or first-party data ingestion. Audit trail for data lineage and GDPR data minimization compliance.',
    `data_clean_room_eligible` BOOLEAN COMMENT 'Indicates whether this audience profile is eligible for inclusion in data clean room matching operations with advertising partners. Eligibility is determined by consent status, CCPA opt-out flag, COPPA protection status, and contractual data sharing agreements.',
    `daypart_preference` STRING COMMENT 'Preferred daypart (time segment of the broadcast day) during which this audience member most frequently views content. Dayparts are standard broadcast industry time segments used for ad scheduling, upfront sales, and audience guarantee reporting.. Valid values are `early_morning|daytime|early_fringe|prime_time|late_night|overnight`',
    `enrichment_source_version` STRING COMMENT 'Version identifier of the third-party enrichment data package (e.g., Nielsen demographic file version, Adobe AEP segment refresh batch ID) used to populate inferred attributes on this profile. Enables data lineage tracing and reproducibility of audience segment definitions.',
    `household_size` STRING COMMENT 'Estimated number of persons in the audience household, derived from Nielsen panel data or set-top box signals. Used in HUT (Homes Using Television) and PUT (Persons Using Television) calculations for audience measurement reporting.',
    `hut_eligible` BOOLEAN COMMENT 'Indicates whether this household-level audience profile is eligible to be counted in HUT (Homes Using Television) calculations. HUT measures the percentage of TV-equipped homes actively watching television during a given time period, a foundational metric for broadcast ratings.',
    `identity_confidence_score` DECIMAL(18,2) COMMENT 'Confidence score (0.00–100.00) representing the reliability of the identity resolution that constructed this audience profile. Higher scores indicate stronger deterministic matching (e.g., authenticated login); lower scores indicate probabilistic device-graph inference. Used to qualify profiles for premium ad targeting.',
    `identity_hash` STRING COMMENT 'SHA-256 pseudonymized hash of the audience members primary identity (e.g., email or subscriber ID) used for cross-platform identity resolution without exposing raw PII. Enables privacy-safe linkage across Nielsen, Adobe AEP, and first-party data sources.. Valid values are `^[a-fA-F0-9]{64}$`',
    `identity_source` STRING COMMENT 'Originating source of the audience identity construction: first_party (subscriber or app registration data), nielsen (Nielsen Media Research panel linkage), adobe_aep (Adobe Experience Platform profile), set_top_box (STB device-level data), clean_room (data clean room match), or modeled (probabilistic inference).. Valid values are `first_party|nielsen|adobe_aep|set_top_box|clean_room|modeled`',
    `income_band` STRING COMMENT 'Inferred household income band derived from third-party demographic enrichment (Nielsen, data clean rooms). Used for premium audience segmentation in upfront and scatter market ad sales, enabling CPM pricing differentiation by audience affluence.. Valid values are `under_25k|25k_50k|50k_75k|75k_100k|100k_150k|over_150k`',
    `inferred_age_band` STRING COMMENT 'Inferred age demographic band for the audience member, derived from Nielsen panel data, set-top box signals, or modeled enrichment. Used for GRP/TRP demographic targeting and ad sales audience guarantees. Not directly collected from the individual.. Valid values are `18-24|25-34|35-44|45-54|55-64|65+`',
    `inferred_gender` STRING COMMENT 'Inferred gender of the audience member derived from panel data or modeled signals. Used for demographic audience targeting in ad sales (GRP/TRP calculations) and programming decisions. Not directly collected.. Valid values are `male|female|unknown`',
    `last_seen_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent observed audience activity event (viewing session, app interaction, or platform login) for this profile. Used to determine audience recency, drive re-engagement campaigns, and calculate viewing recency metrics.',
    `nielsen_grp_index` DECIMAL(18,2) COMMENT 'Indexed GRP (Gross Rating Point) score for this audience profile relative to the total population, sourced from Nielsen Media Research. A GRP index above 100 indicates above-average exposure to rated content. Used in ad sales audience guarantees and upfront negotiations.',
    `panel_weight_factor` DECIMAL(18,2) COMMENT 'Statistical weighting factor assigned by Nielsen to this panel member profile to project panel observations to the total population. Applied in GRP, TRP, HUT, and PUT calculations. Null for non-panel (modeled or first-party only) profiles.',
    `platform_preference` STRING COMMENT 'Primary viewing platform preference inferred from behavioral signals: linear_tv (traditional scheduled broadcast), svod (Subscription Video On Demand), avod (Advertising-Supported VOD), tvod (Transactional VOD), fast (Free Ad-Supported Streaming TV), ott (Over-The-Top), mvpd (Multichannel Video Programming Distributor), or vmvpd (Virtual MVPD). Drives distribution strategy and ad product targeting. [ENUM-REF-CANDIDATE: linear_tv|svod|avod|tvod|fast|ott|mvpd|vmvpd — 8 candidates stripped; promote to reference product]',
    `profile_status` STRING COMMENT '',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this audience profiles measurement data was captured during a Nielsen Sweeps period (intensive ratings measurement period: February, May, July, November). Sweeps data carries higher statistical weight in ratings calculations and programming decisions.',
    `trp_index` DECIMAL(18,2) COMMENT 'Indexed TRP (Target Rating Point) score representing this audience members contribution to a specific demographic target groups rating. Distinct from GRP in that it measures reach within a defined target demographic. Used for demographic-specific ad campaign planning and post-campaign analysis.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this audience profile record, triggered by enrichment refresh, consent status change, identity graph update, or behavioral signal ingestion. Used for data freshness monitoring and incremental processing.',
    `viewing_recency_days` STRING COMMENT 'Number of days since this audience member last engaged with any content on any tracked platform. Used for audience recency segmentation, churn prediction, and re-engagement campaign targeting. Lower values indicate more recently active audiences.',
    `weekly_viewing_frequency` STRING COMMENT 'Average number of distinct viewing sessions per week for this audience member, calculated over a rolling 4-week window. Represents the Frequency dimension of audience measurement (average exposures per viewer). Used in reach and frequency reporting for ad campaign delivery.',
    CONSTRAINT pk_audience_profile PRIMARY KEY(`audience_profile_id`)
) COMMENT 'Anonymized/pseudonymized master record representing a unique audience member or household identity constructed from first-party data (subscriber records, app registrations, set-top box data) and third-party enrichment (Nielsen, Adobe AEP, data clean rooms). Captures hashed identity, device graph linkage, inferred demographic attributes, content affinity scores, platform preferences, viewing recency/frequency, and consent/privacy flags per GDPR, CCPA, and COPPA. Distinct from the subscriber SSOT in the subscriber domain — this is the audience intelligence and behavioral record, not the billing or subscription identity. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`measurement_methodology` (
    `measurement_methodology_id` BIGINT COMMENT 'Unique surrogate identifier for each audience measurement methodology record in the Silver Layer lakehouse. Primary key for this reference master entity. [_canonical_skip_reason: REFERENCE_LOOKUP — this entity is a reference master defining enumerated measurement methodologies; per-role minimums are exempt, but comprehensive coverage is still applied given the business complexity of this domain.]',
    `currency_standard_id` BIGINT COMMENT 'The audience measurement currency standard supported by this methodology, defining the viewing window used for commercial ratings: C3 (average commercial ratings including 3 days of DVR playback), C7 (7-day DVR playback), C35 (35-day), live_plus_same_day, live_only, or custom. The currency standard is the contractual basis for ad sales guarantees and makegood calculations in upfront and scatter markets.',
    `deduplication_method_id` BIGINT COMMENT 'The method used to deduplicate audience reach across platforms or devices when this methodology is applied in cross-platform measurement: probabilistic (statistical modeling), deterministic (identity-matched), hybrid (combination), or none (single-platform only). Affects reported unique reach figures and frequency calculations.',
    `geographic_coverage_level_id` BIGINT COMMENT 'The geographic scope at which this methodology provides valid audience measurement: national (US-wide), dma (Designated Market Area), regional, local (sub-DMA), international, or global. Determines applicability for local vs. national ad sales, retransmission consent negotiations, and blackout enforcement.',
    `methodology_code_id` BIGINT COMMENT 'Short, externally-recognized alphanumeric code uniquely identifying the measurement methodology (e.g., NIELSEN_PPM, NIELSEN_DIARY, STB_DATA, ACR, STREAMING_TELEMETRY, HYBRID_XPLATFORM). Used as a stable business key across systems including Nielsen Media Research Platform and Adobe Experience Platform integrations.',
    `methodology_status_id` BIGINT COMMENT 'Current lifecycle status of the measurement methodology within the organizations audience measurement framework. Active methodologies are used in current ratings and GRP/TRP reporting; deprecated or retired methodologies are retained for historical record interpretation; pilot methodologies are under evaluation for MRC accreditation.',
    `methodology_type_id` BIGINT COMMENT 'Categorical classification of the measurement approach: passive (device-based passive capture such as PPM or STB), diary (self-reported viewer logs), census (full population streaming telemetry), hybrid (cross-platform combination), panel (statistically sampled panel), or acr (Automatic Content Recognition fingerprinting). Governs how ratings and GRP/TRP calculations are interpreted.',
    `mrc_accreditation_code_id` BIGINT COMMENT 'The official accreditation reference number issued by the Media Rating Council (MRC) for this measurement methodology. Used in regulatory filings, ad sales contracts, and audit documentation to reference the specific MRC accreditation certificate.',
    `mrc_accreditation_status_id` BIGINT COMMENT 'Current accreditation status granted by the Media Rating Council (MRC) for this measurement methodology. MRC accreditation is the industry standard for validating audience measurement quality and is required for use in upfront and scatter market ad sales negotiations. Accredited methodologies carry full contractual weight; conditionally accredited methodologies may have usage restrictions.',
    `audience_source_system_code_id` BIGINT COMMENT 'Code identifying the operational system of record from which this methodology definition originates (e.g., NIELSEN_MRP for Nielsen Media Research Platform, ADOBE_AEP for Adobe Experience Platform). Used for data lineage tracking and Silver Layer ingestion audit in the Databricks Lakehouse.',
    `accreditation_body` STRING COMMENT 'The name of the independent body that has accredited or audited this measurement methodology (e.g., Media Rating Council (MRC), Joint Industry Committee (JIC), BARB, Ofcom). Supports multi-market operations where different accreditation bodies govern different geographies.',
    `applicable_market_types` STRING COMMENT 'Comma-separated list of market types where this methodology is valid (e.g., national, local_dma, regional, international). Nielsen PPM is typically used in national and large local DMA markets; diary methodology is used in smaller local markets. Determines which geographic market audience records can be attributed to this methodology.',
    `applicable_platform_types` STRING COMMENT 'Comma-separated list of platform types to which this methodology applies (e.g., linear_tv, ott_streaming, radio, digital_display, podcast). Governs which viewership records and distribution channels can be measured and reported using this methodology. Critical for cross-platform audience deduplication and hybrid measurement.',
    `audience_metric_types` STRING COMMENT 'Comma-separated list of audience metrics that this methodology can produce (e.g., GRP, TRP, HUT, PUT, reach, frequency, share, Nielsen_rating, TSR, CPRP). Governs which KPIs can be reported using data collected under this methodology. GRP (Gross Rating Point), TRP (Target Rating Point), HUT (Homes Using Television), PUT (Persons Using Television), TSR (Time Spent Reading/Viewing), CPRP (Cost Per Rating Point).',
    `consent_mechanism_required` STRING COMMENT 'The type of audience consent mechanism required for data collection under this methodology: opt_in (explicit consent required before data collection), opt_out (data collected unless individual opts out), panel_agreement (panelists sign participation agreement), no_consent_required (census/aggregate data with no individual tracking), or mixed. Governs GDPR, CCPA, and COPPA compliance posture.. Valid values are `opt_in|opt_out|panel_agreement|no_consent_required|mixed`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this measurement methodology record was first created in the Silver Layer data product. Used for data lineage, audit trail, and change management tracking.',
    `cross_platform_capable` BOOLEAN COMMENT 'Indicates whether this methodology supports cross-platform audience deduplication and unified reach/frequency reporting across linear TV, OTT (Over-The-Top), digital, and streaming platforms. Cross-platform capability is required for total audience measurement (TAM) reporting and advanced advertising guarantees.',
    `data_collection_mechanism` STRING COMMENT 'The specific technical mechanism by which audience exposure data is collected: PPM device (Portable People Meter worn by panelists), diary form (paper or electronic self-report), STB return path (Set-Top Box return-path data), ACR fingerprint (Automatic Content Recognition audio/video fingerprinting), SDK telemetry (streaming app software development kit), pixel tracking (web/app pixel), or hybrid combination. Determines data fidelity and applicable use cases. [ENUM-REF-CANDIDATE: ppm_device|diary_form|stb_return_path|acr_fingerprint|sdk_telemetry|pixel_tracking|hybrid — 7 candidates stripped; promote to reference product]',
    `data_retention_days` STRING COMMENT 'The maximum number of days that raw audience measurement data collected under this methodology may be retained, as governed by privacy regulations (GDPR, CCPA) and MRC audit requirements. After this period, data must be anonymized or deleted. Drives data lifecycle management in the lakehouse.',
    `daypart_applicability` STRING COMMENT 'Comma-separated list of broadcast dayparts for which this methodology produces valid audience estimates (e.g., early_morning, daytime, early_fringe, prime_time, late_news, overnight). Daypart is a standard time segment of the broadcast day used in ad scheduling and CPM pricing. Some methodologies may have reduced reliability in overnight or early morning dayparts.',
    `demographic_granularity` STRING COMMENT 'Describes the level of demographic segmentation this methodology supports (e.g., age_sex_only, age_sex_income, full_psychographic, household_level_only). Determines which audience segments can be reported for ad targeting, TRP calculations, and upfront sales guarantees.',
    `effective_from_date` DATE COMMENT 'The date from which this measurement methodology became or becomes valid for use in audience measurement, ratings reporting, and ad sales guarantees. Supports temporal validity tracking for methodology versioning and historical ratings restatement.',
    `effective_until_date` DATE COMMENT 'The date on which this measurement methodology ceases to be valid for new audience measurement records. Null indicates the methodology is currently open-ended and active. Used to enforce temporal validity in ratings lookups and prevent application of deprecated methodologies to new viewership data.',
    `is_sweeps_applicable` BOOLEAN COMMENT 'Indicates whether this measurement methodology is used or enhanced during Nielsen Sweeps periods (February, May, July, November) — the intensive ratings measurement periods used to set local advertising rates. Diary methodology is exclusively sweeps-based in many markets; PPM operates year-round.',
    `methodology_description` STRING COMMENT 'Detailed narrative description of how the measurement methodology works, including data collection mechanism, panel recruitment approach, weighting procedures, and any known limitations. Used by ad sales teams, programming analysts, and regulatory compliance officers to understand how viewership and rating records are produced.',
    `methodology_name` STRING COMMENT 'Full human-readable name of the audience measurement methodology (e.g., Nielsen Portable People Meter, Nielsen Diary, Set-Top Box Data, Automatic Content Recognition, Streaming Platform Telemetry, Hybrid Cross-Platform Measurement). Used in reports, dashboards, and regulatory filings.',
    `mrc_accreditation_date` DATE COMMENT 'The date on which the Media Rating Council (MRC) granted or last renewed accreditation for this measurement methodology. Used to track accreditation currency and trigger renewal workflows.',
    `mrc_accreditation_expiry_date` DATE COMMENT 'The date on which the current MRC accreditation for this methodology expires. Methodologies with lapsed accreditation cannot be used in contractually binding audience guarantees for upfront or scatter market ad sales. Triggers compliance review and renewal workflows.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, known limitations, special handling instructions, or contextual information about this measurement methodology. Examples include known panel biases, market-specific adjustments, or transition notes when migrating from one methodology version to another.',
    `privacy_compliance_framework` STRING COMMENT 'Comma-separated list of privacy and data protection frameworks under which this methodologys data collection and processing is compliant (e.g., GDPR, CCPA, COPPA, TCPA). GDPR governs EU audience data; CCPA governs California viewer data; COPPA governs childrens content measurement. Required for regulatory reporting and data governance.',
    `reporting_frequency` STRING COMMENT 'The cadence at which audience measurement data is reported using this methodology: overnight (daily ratings delivery), weekly, monthly, quarterly, or sweeps_only (data available only during Nielsen Sweeps measurement periods in February, May, July, and November). Governs scheduling of ad sales reporting and programming analysis cycles.. Valid values are `overnight|weekly|monthly|quarterly|sweeps_only`',
    `reporting_latency_hours` STRING COMMENT 'The typical number of hours between the audience exposure event and the availability of processed, reportable ratings data using this methodology. Nielsen PPM typically delivers overnight ratings within 24 hours; diary methodology may have 2–4 week latency. Critical for ad sales makegoods, scatter market decisions, and programming adjustments.',
    `sample_size_minimum` STRING COMMENT 'The minimum number of panelists or measurement units required for this methodology to produce statistically valid audience estimates. Below this threshold, ratings data is considered unreliable and may be suppressed or flagged. Enforced per MRC accreditation requirements and Nielsen panel design standards.',
    `sample_size_target` STRING COMMENT 'The ideal or design target number of panelists or measurement units for this methodology to achieve the desired statistical confidence level and margin of error. Used in panel management and methodology performance monitoring against MRC accreditation benchmarks.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this measurement methodology record was most recently modified in the Silver Layer data product. Used for incremental load detection, change data capture, and audit compliance.',
    `vendor_methodology_version` STRING COMMENT 'The vendor-assigned version identifier for this measurement methodology (e.g., PPM v3.2, C3, C7, P2+ 2023). Version changes may affect historical comparability of ratings data and require restatement of audience guarantees. Critical for audit trails and makegood calculations.. Valid values are `^[A-Za-z0-9._-]{1,30}$`',
    `vendor_name` STRING COMMENT 'The name of the third-party vendor or research firm that operates or provides this measurement methodology (e.g., Nielsen, Comscore, Kantar, VideoAmp, iSpot.tv). Used for vendor management, contract tracking, and source system attribution in the Nielsen Media Research Platform integration.',
    CONSTRAINT pk_measurement_methodology PRIMARY KEY(`measurement_methodology_id`)
) COMMENT 'Reference master defining the audience measurement methodologies in use — Nielsen PPM (Portable People Meter), Nielsen Diary, Set-Top Box (STB) data, ACR (Automatic Content Recognition), streaming platform telemetry, and hybrid cross-platform measurement. Captures methodology code, description, applicable market types, sample size requirements, reporting latency, and accreditation body (MRC — Media Rating Council). Governs how each viewership and rating record is interpreted. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`segment` (
    `segment_id` BIGINT COMMENT 'Unique surrogate identifier for the audience segment record in the Silver Layer lakehouse. Primary key for this master resource entity.',
    `activation_status_id` BIGINT COMMENT 'Current lifecycle state of the segment governing whether it is available for use in ad targeting, campaign activation, or content personalization. draft indicates under construction; pending_review awaits compliance or data governance approval; active is live and deployable; inactive is suspended; archived is retired.',
    `aep_segment_code_id` BIGINT COMMENT 'The segment identifier as defined and managed within Adobe Experience Platform (AEP). Used for digital audience activation, personalization journeys, and cross-channel targeting. Enables synchronization between the internal audience_segment master record and the AEP segment definition for OTT and digital platforms.',
    `coppa_declaration_id` BIGINT COMMENT 'Foreign key linking to compliance.coppa_declaration. Business justification: Audience segments targeting children must link to COPPA compliance declarations. Ensures parental consent mechanisms are in place before segment activation for advertising or analytics.',
    `nielsen_segment_code_id` BIGINT COMMENT 'The corresponding segment or audience cell identifier within the Nielsen Media Research Platform. Enables direct linkage to Nielsen ratings data, GRP/TRP delivery reports, and demographic reach/frequency outputs. Used for reconciliation between internal segment definitions and Nielsen-measured audience delivery.',
    `segment_category_id` BIGINT COMMENT 'Business-facing category grouping segments for portfolio management and reporting (e.g., Ad Targeting, Programming Strategy, Content Personalization, Subscriber Retention, Regulatory Reporting). Enables segment library organization in Salesforce Media Cloud and Adobe AEP. [ENUM-REF-CANDIDATE: ad_targeting|programming_strategy|content_personalization|subscriber_retention|regulatory_reporting|audience_research — promote to reference product]',
    `segment_code_id` BIGINT COMMENT 'Externally-known, human-readable business identifier for the segment used across systems such as Adobe Experience Platform (AEP), Nielsen, and Salesforce Media Cloud. Serves as the canonical cross-system reference code (e.g., SEG-DEMO-F25-54-OTT).',
    `segment_type_id` BIGINT COMMENT 'Classification of the segment by the primary methodology used to define it. Demographic segments are built on age/gender/HUT criteria; behavioral on viewing patterns; psychographic on interests/attitudes; contextual on content affinity; lookalike on modeled similarity to a seed audience.',
    `age_range_max` STRING COMMENT 'Maximum age (inclusive) of the primary demographic target for this segment, expressed in years. Used with age_range_min to define the Nielsen demographic cell. A null value indicates an open-ended upper bound (e.g., 55+ segments).',
    `age_range_min` STRING COMMENT 'Minimum age (inclusive) of the primary demographic target for this segment, expressed in years. Used in conjunction with age_range_max to define the Nielsen demographic cell (e.g., 25 for the Adults 25-54 standard Nielsen demo). Null if the segment is not age-bounded.',
    `approved_by` STRING COMMENT 'Name or identifier of the data governance or compliance approver who authorized this segment for activation, particularly for segments involving sensitive demographic data, COPPA-restricted audiences, or GDPR-regulated EU audiences. Supports audit trail requirements.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when this segment received formal data governance or compliance approval for activation. Distinct from created_timestamp — captures the approval lifecycle event. Required for GDPR accountability documentation and internal audit trails. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `content_genre_affinity` STRING COMMENT 'Primary content genre(s) this segment shows strong viewership affinity toward, used for programming strategy alignment and contextual ad targeting (e.g., drama,sports,news). Sourced from Nielsen viewing behavior data or Adobe AEP content interaction signals. Informs content acquisition decisions and ad pod placement strategy.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this audience segment record was first created in the system. Serves as the audit creation timestamp for data lineage, governance, and Silver Layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_source` STRING COMMENT 'Identifies the primary data origin used to construct the segment. nielsen indicates Nielsen Media Research Platform ratings and demographic data; adobe_aep indicates Adobe Experience Platform behavioral profiles; first_party indicates proprietary subscriber or registration data; third_party indicates licensed external data; hybrid indicates a combination of multiple sources.. Valid values are `nielsen|adobe_aep|first_party|third_party|hybrid`',
    `daypart_applicability` STRING COMMENT 'Broadcast daypart(s) for which this segment is most relevant or has been validated, expressed as a comma-delimited list of standard daypart labels (e.g., primetime,late_night). Daypart is a standard media-buying time segment of the broadcast day used in ad scheduling and upfront sales. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|primetime|late_news|late_night|overnight — promote to reference product]',
    `definition_logic` STRING COMMENT 'The rule-based or SQL/JSON expression that defines segment membership criteria as implemented in Adobe AEP or Nielsen. Captures the inclusion/exclusion logic (e.g., age range, viewing frequency thresholds, content genre affinity, platform usage) used to qualify audience members into this segment.',
    `segment_description` STRING COMMENT 'Detailed narrative description of the segments business purpose, defining criteria, and intended use cases. Provides context for ad sales teams, programmers, and data analysts on what the segment represents and how it should be applied.',
    `effective_from` DATE COMMENT 'The date from which this segment definition is considered valid and available for business use. Segments may be pre-built ahead of upfront sales seasons or campaign launches. Enables temporal validity management for segment versioning and historical reporting.',
    `effective_until` DATE COMMENT 'The date after which this segment definition is no longer valid for new activations. Null indicates an open-ended segment with no planned expiry. Used to manage seasonal segments (e.g., sweeps-period segments), campaign-specific segments, and segments tied to expiring data licensing agreements.',
    `estimated_reach` BIGINT COMMENT 'Estimated number of unique individuals (persons or households) who qualify for this segment at the time of last refresh. Reach is a core Nielsen and IAB metric used in ad sales proposals, GRP/TRP calculations, and CPM pricing. Distinct from impressions — counts unique audience members, not exposures.',
    `estimated_reach_unit` STRING COMMENT 'Unit of measurement for the estimated_reach figure. persons aligns with Nielsen PUT (Persons Using Television) methodology; households aligns with HUT (Homes Using Television); devices applies to digital/OTT platform segments measured by device-level identity.. Valid values are `persons|households|devices`',
    `gender_target` STRING COMMENT 'Gender composition target for the segment as defined in Nielsen demographic cells and ad sales targeting parameters. all indicates gender-neutral targeting. Used in GRP (Gross Rating Point) and TRP (Target Rating Point) calculations for ad campaign planning.. Valid values are `male|female|all|non_binary`',
    `grp_index` DECIMAL(18,2) COMMENT 'The GRP (Gross Rating Point) index value representing this segments relative audience weight as a percentage of the total universe. GRP is a fundamental media planning metric equal to Reach × Frequency. Used in upfront and scatter market ad sales to price inventory and measure campaign delivery against this segment.',
    `hut_put_basis` STRING COMMENT 'Indicates whether the segments reach and rating metrics are calculated on a HUT (Homes Using Television) or PUT (Persons Using Television) basis. HUT is household-level measurement; PUT is person-level. This distinction governs how GRP/TRP values are interpreted and how the segment is applied in Nielsen-based ad sales planning.. Valid values are `hut|put`',
    `income_bracket` STRING COMMENT 'Household income tier associated with the segments demographic composition, used in premium ad targeting and CPM (Cost Per Mille) pricing. Expressed as a standardized range label (e.g., $75K-$100K HHI, $100K+ HHI). Sourced from Nielsen MRI-Simmons or first-party subscriber data. [ENUM-REF-CANDIDATE: under_25k|25k_50k|50k_75k|75k_100k|100k_150k|150k_plus — promote to reference product]',
    `is_dai_eligible` BOOLEAN COMMENT 'Indicates whether this segment is approved and technically configured for use in DAI (Dynamic Ad Insertion) workflows on OTT and streaming platforms. DAI-eligible segments can be activated in real-time ad decisioning systems integrated with Akamai CDN and programmatic ad servers for addressable advertising.',
    `is_sweeps_validated` BOOLEAN COMMENT 'Indicates whether this segments reach and demographic composition estimates have been validated using Nielsen Sweeps period data (the intensive ratings measurement periods in February, May, July, and November). Sweeps-validated segments carry higher confidence for upfront ad sales commitments and programming decisions.',
    `last_refresh_timestamp` TIMESTAMP COMMENT 'The date and time when the segment membership, reach estimates, and demographic composition were last recalculated from source data. Used to assess data freshness for ad sales proposals and campaign activation. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this audience segment record was last updated. Tracks changes to segment definition, status, reach estimates, or compliance flags. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and audit trail maintenance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `segment_name` STRING COMMENT 'Human-readable display name for the audience segment as it appears in ad sales proposals, programming strategy decks, and campaign targeting UIs (e.g., Women 25-54 OTT Heavy Viewers). Corresponds to the segment label in Adobe AEP and Salesforce Media Cloud.',
    `notes` STRING COMMENT 'Free-text field for additional business context, caveats, or operational notes about the segment that do not fit structured fields. Examples include data quality warnings, known limitations of the definition logic, special handling instructions for ad sales, or notes on upcoming segment retirement.',
    `owner_team` STRING COMMENT 'The business team or department that owns and is accountable for this segments definition, quality, and lifecycle management (e.g., Ad Sales Research, Audience Analytics, Programming Strategy, Digital Marketing). Used for data governance, access control, and segment portfolio management.',
    `platform_applicability` STRING COMMENT 'Comma-delimited list of distribution platforms for which this segment is valid and activated (e.g., linear,ott,avod,svod,fast). Governs where the segment can be applied for ad targeting or content personalization across Linear, OTT (Over-The-Top), AVOD (Advertising-Supported Video On Demand), SVOD (Subscription Video On Demand), and FAST (Free Ad-Supported Streaming Television) channels. [ENUM-REF-CANDIDATE: linear|ott|avod|svod|tvod|fast|social|digital_display — promote to reference product]',
    `refresh_frequency` STRING COMMENT 'How frequently the segment membership and reach estimates are recalculated and updated from source systems (Nielsen, Adobe AEP, or first-party data). Governs data freshness SLAs for ad targeting activation. real_time applies to DAI-eligible programmatic segments; daily is standard for digital; weekly/monthly for Nielsen-based linear segments.. Valid values are `real_time|daily|weekly|monthly|quarterly|on_demand`',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `trp_index` DECIMAL(18,2) COMMENT 'The TRP (Target Rating Point) index value representing this segments rating within its specific target demographic universe. TRP is the targeted equivalent of GRP, measuring delivery efficiency against the defined demographic cell. Critical for ad sales pricing, makegoods calculations, and CPRP (Cost Per Rating Point) negotiations.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `version_number` STRING COMMENT 'Monotonically incrementing version counter for the segment definition. Incremented each time the segments definition logic, demographic criteria, or platform applicability is materially changed. Enables segment versioning for historical campaign attribution — ad campaigns reference the segment version active at time of booking.',
    CONSTRAINT pk_segment PRIMARY KEY(`segment_id`)
) COMMENT 'Master record for a defined, reusable audience segment built from demographic, behavioral, and psychographic criteria for use in ad targeting, programming strategy, and content personalization. Captures segment name, definition logic, estimated size, demographic composition, platform applicability, activation status, and data source (Nielsen, Adobe AEP, first-party). Distinct from demographic_segment (which is a reference classification) — this is an operationally managed, business-owned targeting segment. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`cross_platform_measurement` (
    `cross_platform_measurement_id` BIGINT COMMENT 'Unique surrogate identifier for each cross-platform audience measurement record in the Silver layer lakehouse. Primary key for this transactional entity.',
    `campaign_id` BIGINT COMMENT 'Reference to the advertising campaign flight for which this cross-platform measurement is being reported. Enables audience currency reconciliation for converged TV buying. Nullable when measurement is content-centric rather than campaign-centric.',
    `compliance_content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Cross-platform metrics require rating context for regulatory reporting (childrens programming hours) and advertiser suitability verification across linear and streaming delivery.',
    `title_id` BIGINT COMMENT 'Reference to the content title or program for which this cross-platform audience measurement is recorded. Links to the content master data product in the Content domain.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Cross-platform metrics attribute audience delivery across linear/digital to content-producing cost centers. Content ROI analysis and budget allocation decisions require linking multi-platform performa',
    `audience_daypart_code_id` BIGINT COMMENT 'Broadcast daypart classification for the measurement period, representing the time segment of the broadcast day. [ENUM-REF-CANDIDATE: EAM|AM|DAYTIME|EARLY_FRINGE|PRIME|LATE_FRINGE|OVERNIGHT — promote to reference product if additional dayparts are required]',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Cross-platform measurements target specific demographic segments for deduplicated reach calculations. The target_demographic string should be replaced with FK to demographic_segment for consistency wi',
    `distribution_type_id` BIGINT COMMENT 'Primary distribution model classification for the content being measured: linear for traditional scheduled broadcast; vod for generic on-demand; svod for subscription streaming; avod for ad-supported streaming; tvod for transactional on-demand; fast for free ad-supported streaming TV; social for social video platforms. [ENUM-REF-CANDIDATE: linear|vod|svod|avod|tvod|fast|social — 7 candidates stripped; promote to reference product]',
    `audience_isan_code_id` BIGINT COMMENT 'International Standard Audiovisual Number (ISAN) for the content title being measured, providing a globally unique, persistent identifier for the audiovisual work. Enables cross-system content identification and rights reconciliation.',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Cross-platform measurements are aggregated by DMA/market. The geographic_market_code should be replaced with FK to market_coverage for consistency with nielsen_rating and other measurement products.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Cross-platform measurement requires specialized analysts to perform deduplication, validate MRC-accredited methodologies, reconcile linear/OTT/MVPD impressions, and certify total audience metrics. Ana',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Cross-platform measurements use specific methodologies for deduplication and aggregation. The measurement_methodology string and measurement_vendor should be replaced with FK to measurement_methodolog',
    `audience_measurement_status_id` BIGINT COMMENT 'Current lifecycle state of the cross-platform measurement record. draft indicates data is being assembled; preliminary indicates initial estimate released; certified indicates MRC-audited final figure; revised indicates a post-certification correction; archived indicates superseded by a newer measurement.',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Cross-platform measurement is a key differentiator in modern media sales, directly referenced when pitching multi-platform opportunities. Sales teams use cross-platform reach data to justify premium p',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Cross-platform measurement must attribute audience delivery to specific distribution/carriage partners for revenue share calculations and partner performance evaluation. Essential for multi-platform p',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level cross-platform measurement is required for total audience delivery verification, especially for time-shifted viewing and multi-platform distribution. Essential for C3/C7 ratings and adve',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Cross-platform measurement aggregates linear TV + streaming + social video performance for specific production projects. Required for total audience reporting, C3/C7 ratings, and advertiser delivery v',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Cross-platform audience drives profit center revenue allocation across distribution channels. Segment reporting for investors and internal management reviews require tying total audience delivery to n',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Cross-platform measurements during sweeps periods are critical for upfront negotiations and guarantee reconciliation. The is_sweeps_period flag indicates relevance, but the specific sweeps period shou',
    `audience_share` DECIMAL(18,2) COMMENT 'Percentage of the total viewing audience (HUT or PUT) that was watching this specific content or channel during the measurement period. Calculated as the program rating divided by HUT or PUT. Key programming performance indicator.',
    `average_frequency` DECIMAL(18,2) COMMENT 'Average number of times a unique individual in the deduplicated reach was exposed to the content or campaign across all platforms within the measurement period. Calculated as total impressions divided by deduplicated reach.',
    `co_viewing_adjustment_factor` DECIMAL(18,2) COMMENT 'Multiplicative adjustment factor applied to account for co-viewing behavior (multiple persons watching on a single device/screen), particularly relevant for connected TV and OTT platforms. Values greater than 1.0 indicate upward adjustment for co-viewing. Sourced from Nielsen co-viewing methodology.',
    `content_genre` STRING COMMENT 'Genre classification of the content title being measured (e.g., Drama, News, Sports, Reality, Comedy, Documentary). Used for audience segmentation analysis and programming strategy reporting. [ENUM-REF-CANDIDATE: drama|news|sports|reality|comedy|documentary|talk|game_show|animation|other — promote to reference product]',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this cross-platform measurement record was first ingested into the Silver layer lakehouse.',
    `cross_platform_grp` DECIMAL(18,2) COMMENT 'Gross Rating Point (GRP) calculated across all measured platforms, representing the sum of ratings for all platform exposures within the target universe. Equals total impressions divided by the target universe population, multiplied by 100. Primary audience currency for converged TV ad buying.',
    `cross_platform_trp` DECIMAL(18,2) COMMENT 'Target Rating Point (TRP) calculated across all measured platforms for the specified target demographic segment. Measures GRP within the defined target audience, used for demographic-specific ad buying and campaign performance evaluation.',
    `currency_version` STRING COMMENT 'Version identifier of the audience measurement currency standard applied to this record (e.g., Nielsen ONE v2.1, Comscore Campaign Ratings v3.0). Supports multi-currency and currency transition tracking as the industry evolves from legacy Nielsen C3/C7 to cross-platform currencies.',
    `data_source_systems` STRING COMMENT 'Pipe-delimited list of operational source systems that contributed data to this cross-platform measurement record (e.g., Nielsen Media Research Platform|Adobe Experience Platform). Supports data lineage, audit, and methodology transparency requirements.',
    `deduplicated_reach` BIGINT COMMENT 'Total count of unique, unduplicated individuals (persons) who were exposed to the content or campaign across all measured platforms within the measurement period. Core audience currency metric for converged TV buying. Expressed as absolute person count.',
    `fast_channel_impressions` BIGINT COMMENT 'Audience impressions attributed to Free Ad-Supported Streaming Television (FAST) channels within the measurement period. Represents the growing ad-supported streaming audience segment.',
    `hut_rating` DECIMAL(18,2) COMMENT 'Homes Using Television (HUT) rating for the measurement period, representing the percentage of all television households with at least one TV set in use during the measured time period. Used for share calculations and programming decisions.',
    `is_data_suppressed` BOOLEAN COMMENT 'Indicates whether this measurement record has been suppressed from reporting due to insufficient panel sample size, MRC minimum reporting thresholds, or privacy regulations (GDPR/CCPA). Suppressed records are retained for audit but excluded from audience currency reporting.',
    `is_mrc_accredited` BOOLEAN COMMENT 'Indicates whether this measurement was produced using a methodology that holds current Media Rating Council (MRC) accreditation for cross-platform measurement. MRC accreditation is required for use as official audience currency in upfront and scatter market ad transactions.',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether this measurement falls within a Nielsen sweeps period (February, May, July, November), which represents an intensive ratings measurement window used for programming and ad rate decisions.',
    `linear_impressions` BIGINT COMMENT 'Audience impressions attributed to traditional linear broadcast television (over-the-air, cable, satellite) within the measurement period. Component of the platform-level audience breakdown.',
    `measurement_period_end` DATE COMMENT 'The last date of the audience measurement observation window, aligned to the content airing schedule or campaign flight end.',
    `measurement_period_start` DATE COMMENT 'The first date of the audience measurement observation window, aligned to the content airing schedule or campaign flight start. Used for sweeps period identification and daypart analysis.',
    `measurement_reference_number` STRING COMMENT 'Externally-known business identifier for this cross-platform measurement record, used in reporting, ad sales proposals, and audience currency reconciliation. Sourced from Nielsen Media Research Platform or internal measurement workflow.',
    `measurement_timestamp` TIMESTAMP COMMENT 'The principal real-world timestamp representing when the audience measurement observation period was captured or the measurement run was executed. Distinct from record audit timestamps.',
    `mvpd_impressions` BIGINT COMMENT 'Audience impressions attributed to Multichannel Video Programming Distributor (MVPD) and virtual MVPD (vMVPD) platforms, including cable, satellite, and virtual pay-TV providers within the measurement period.',
    `nielsen_rating` DECIMAL(18,2) COMMENT 'The Nielsen Rating for the content or program within the measurement period, representing the percentage of all television households or persons in the universe tuned to the program. The foundational audience currency metric for linear broadcast.',
    `ott_streaming_impressions` BIGINT COMMENT 'Audience impressions attributed to Over-The-Top (OTT) and Subscription Video On Demand (SVOD) streaming platforms within the measurement period. Includes authenticated streaming on connected TV, mobile, and desktop devices.',
    `panel_sample_size` STRING COMMENT 'Number of panel households or persons in the Nielsen (or equivalent vendor) measurement panel that contributed to this cross-platform measurement. Indicates statistical reliability; low sample sizes may trigger data suppression per MRC minimum reporting standards.',
    `put_rating` DECIMAL(18,2) COMMENT 'Persons Using Television (PUT) rating for the measurement period, representing the percentage of all persons in the universe who are watching television during the measured time period. Used for person-level audience share calculations.',
    `social_video_impressions` BIGINT COMMENT 'Audience impressions attributed to social video platforms (e.g., YouTube, Facebook Video, TikTok, Instagram Reels) within the measurement period. Enables full cross-platform audience aggregation.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `target_universe_size` BIGINT COMMENT 'The estimated total population size of the target demographic universe used as the denominator for GRP and TRP calculations. Sourced from Nielsen universe estimates updated annually.',
    `total_impressions` BIGINT COMMENT 'Total number of audience exposures (impressions) across all platforms within the measurement period, including duplicate exposures across platforms. Used for CPM-based advertising currency and GRP calculation inputs.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this cross-platform measurement record was last modified, supporting data lineage and revision tracking.',
    CONSTRAINT pk_cross_platform_measurement PRIMARY KEY(`cross_platform_measurement_id`)
) COMMENT 'Transactional record aggregating deduplicated audience measurement across linear broadcast, OTT/SVOD streaming, MVPD/vMVPD, FAST channels, and social video platforms for a specific content title or campaign flight. Captures deduplicated reach, total impressions, platform-level audience breakdown, co-viewing adjustment factor, cross-platform GRP/TRP, and big data + panel fusion methodology indicators. Aligns with Nielsen ONE, Comscore, and MRC cross-platform measurement standards. Enables unified audience currency reporting for converged TV buying. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`market_distribution_agreement` (
    `market_distribution_agreement_id` BIGINT COMMENT 'Unique surrogate identifier for this market-partner distribution agreement record',
    `audience_agreement_status_id` BIGINT COMMENT 'Current lifecycle status of this market-partner distribution agreement.',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to the DMA/market coverage area where this distribution agreement applies',
    `must_carry_status_id` BIGINT COMMENT 'FCC regulatory classification for this market-partner carriage relationship: must-carry obligation, retransmission consent negotiation, or not applicable.',
    `partner_id` BIGINT COMMENT 'Foreign key linking to the distribution partner (MVPD, vMVPD, affiliate, syndicator) party to this agreement',
    `performance_tier_id` BIGINT COMMENT 'Classification of the partners performance in this specific market based on subscriber growth, payment compliance, and audience delivery metrics.',
    `carriage_fee_per_subscriber` DECIMAL(18,2) COMMENT 'Negotiated monthly or annual fee paid per subscriber for carriage rights in this specific market. This rate varies by market size, partner type, and competitive dynamics.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this market distribution agreement record was created.',
    `effective_end_date` DATE COMMENT 'Date when this market-specific distribution agreement expires or terminates. Null indicates an evergreen or currently active agreement.',
    `effective_start_date` DATE COMMENT 'Date when this market-specific distribution agreement becomes effective and carriage rights commence.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this distribution agreement grants exclusive carriage rights to the partner in this market, preventing competing distribution deals.',
    `last_renewal_date` DATE COMMENT 'Date when this market-specific agreement was most recently renewed or renegotiated.',
    `next_negotiation_date` DATE COMMENT 'Scheduled date for the next contract renegotiation or renewal discussion for this market-partner relationship.',
    `penetration_rate` DECIMAL(18,2) COMMENT 'Percentage of total TV households in the market that subscribe to this partners service. Calculated as subscriber_count divided by market TV household universe.',
    `retransmission_consent_granted` BOOLEAN COMMENT 'Indicates whether retransmission consent has been granted to this partner for broadcast signals in this market, per FCC regulations.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `subscriber_count` BIGINT COMMENT 'Current number of subscribers the partner serves in this market. Used to calculate total carriage fees and assess market penetration.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this market distribution agreement record was last modified.',
    CONSTRAINT pk_market_distribution_agreement PRIMARY KEY(`market_distribution_agreement_id`)
) COMMENT 'This association product represents the contractual distribution agreement between a market coverage area and a distribution partner. It captures market-specific carriage terms, subscriber economics, and territorial rights that exist only in the context of this market-partner relationship. Each record links one DMA/market to one distribution partner with commercial terms, performance metrics, and exclusivity provisions that vary by market-partner combination.. Existence Justification: Distribution partners (MVPDs, vMVPDs, affiliates, syndicators) operate across multiple geographic markets, each with market-specific carriage agreements, subscriber counts, and commercial terms. Conversely, each DMA/market has multiple distribution partners competing or coexisting with different penetration rates, carriage fees, and exclusivity provisions. This is the operational foundation of territorial rights management and market-based distribution economics in media broadcasting. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`talent_demographic_appeal` (
    `talent_demographic_appeal_id` BIGINT COMMENT 'Unique surrogate identifier for each talent demographic appeal measurement record. Primary key for the association.',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to the demographic segment for which this appeal measurement applies',
    `audience_measurement_status_id` BIGINT COMMENT 'Lifecycle status of this appeal measurement record. Current measurements are used for active casting and programming decisions; Historical measurements are retained for trend analysis.',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to the talent profile being measured for demographic appeal',
    `appeal_index` DECIMAL(18,2) COMMENT 'Normalized appeal index score measuring the talents overall appeal within this specific demographic segment. Scale and methodology aligned with industry standards for talent appeal measurement.',
    `awareness_percentage` DECIMAL(18,2) COMMENT 'Percentage of the demographic segment that is aware of or recognizes this talent. Key metric for talent reach and recognition within the target demographic.',
    `casting_recommendation_flag` BOOLEAN COMMENT 'Indicates whether this talent is recommended for casting in content targeting this demographic segment based on appeal thresholds. Used by casting directors and programming teams.',
    `confidence_interval` DECIMAL(18,2) COMMENT 'Statistical confidence interval (margin of error) for the appeal metrics in this measurement, expressed as a percentage. Used to assess measurement precision.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `favorability_rating` DECIMAL(18,2) COMMENT 'Favorability or likability rating of the talent among respondents in this demographic segment who are aware of the talent. Measures positive sentiment.',
    `measurement_date` DATE COMMENT 'The date when this appeal measurement was conducted or published. Critical for tracking appeal trends over time and ensuring measurement currency.',
    `measurement_methodology` STRING COMMENT 'The research methodology used to measure this talents appeal within this demographic (e.g., Q_Score_Standard, Custom_Survey, Panel_Research). Ensures comparability and appropriate interpretation of metrics.',
    `measurement_vendor` STRING COMMENT 'The research vendor or organization that conducted the appeal measurement (e.g., Marketing Evaluations Inc., Nielsen, custom internal research). Used for data provenance and methodology validation.',
    `q_score` DECIMAL(18,2) COMMENT 'The Marketing Evaluations Q Score for this talent within this demographic segment. Measures familiarity and appeal, used industry-wide for talent valuation and casting decisions.',
    `record_created_timestamp` TIMESTAMP COMMENT 'System timestamp when this talent demographic appeal record was created in the data platform.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this talent demographic appeal record was last updated.',
    `sample_size` STRING COMMENT 'The number of respondents from this demographic segment included in the appeal measurement study. Used to assess statistical confidence and measurement reliability.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `trend_direction` STRING COMMENT 'The directional trend of this talents appeal within this demographic compared to prior measurements (Rising, Stable, Declining). Used for talent investment and booking strategy.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_talent_demographic_appeal PRIMARY KEY(`talent_demographic_appeal_id`)
) COMMENT 'This association product represents the measured appeal and awareness metrics of talent across specific demographic segments. It captures Q Score ratings, awareness percentages, favorability ratings, and appeal indices that exist only in the context of a specific talent-demographic combination. Each record links one talent_profile to one demographic_segment with measurement data used for casting decisions, talent booking, programming strategy, and advertising sales targeting. This is the operational system of record for talent appeal research used by programming, casting, and ad sales teams.. Existence Justification: In media broadcasting operations, talent appeal is measured across multiple demographic segments simultaneously (e.g., a host has different Q Scores for A18-49, W25-54, M18-34), and each demographic segment has appeal measurements for multiple talent profiles. Casting directors, programming strategists, and ad sales teams actively query and manage this appeal data to make talent booking decisions, programming placement, and advertising targeting decisions. This is operational audience research data, not an analytical correlation. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`partner_demographic_target` (
    `partner_demographic_target_id` BIGINT COMMENT 'Unique surrogate identifier for each partner demographic targeting agreement record',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to the demographic segment being targeted in this partner agreement',
    `partner_id` BIGINT COMMENT 'Foreign key linking to the partner who is targeting this demographic segment',
    `priority_tier_id` BIGINT COMMENT 'Priority classification for this demographic target within the partner relationship. Tier 1 represents highest priority demographics for the partner with premium inventory allocation and first-right-of-refusal on premium placements.',
    `target_status_id` BIGINT COMMENT 'Current lifecycle status of this demographic targeting agreement. Active indicates currently in-force, Suspended indicates temporarily paused, Expired indicates contract term ended.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this partner demographic target record was first created',
    `effective_end_date` DATE COMMENT 'Date when this partner demographic targeting agreement expires or is superseded. Null indicates an ongoing evergreen agreement.',
    `effective_start_date` DATE COMMENT 'Date when this partner demographic targeting agreement becomes active. Aligns with contract effective dates or campaign flight dates.',
    `guaranteed_rating` DECIMAL(18,2) COMMENT 'Contractually guaranteed audience rating percentage for this demographic segment that the broadcaster commits to deliver to the partner. Used for make-good calculations if performance falls short.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'System timestamp when this partner demographic target record was last updated',
    `performance_index` DECIMAL(18,2) COMMENT 'Performance tracking index measuring actual delivery against guaranteed rating for this partner-demographic target. Values above 1.0 indicate over-delivery, below 1.0 indicate under-delivery requiring make-goods.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `target_cpm` DECIMAL(18,2) COMMENT 'Negotiated cost per thousand impressions (CPM) rate for this partner-demographic combination. This is the commercial pricing agreed between the broadcaster and partner for reaching this specific demographic segment.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_partner_demographic_target PRIMARY KEY(`partner_demographic_target_id`)
) COMMENT 'This association product represents the contractual audience targeting agreement between partners and demographic segments. It captures partner-specific demographic targeting strategies where each partner (advertiser, agency, network) negotiates specific performance guarantees, CPM rates, and priority levels for each demographic segment they target. Each record links one partner to one demographic segment with commercial terms that exist only in the context of this business relationship.. Existence Justification: In media broadcasting operations, partners (advertisers, agencies, networks) negotiate targeting agreements for multiple demographic segments simultaneously, each with distinct CPM rates, performance guarantees, and priority levels. Conversely, each demographic segment (e.g., A18-49, W25-54) is targeted by multiple partners with varying commercial terms. Media sales teams actively manage these partner-demographic targeting agreements as contractual commitments that drive inventory allocation, pricing, and make-good obligations. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`segment_regulatory_compliance` (
    `segment_regulatory_compliance_id` BIGINT COMMENT 'Unique surrogate identifier for this segment-obligation compliance record. Primary key.',
    `audience_compliance_status_id` BIGINT COMMENT 'Current compliance state of this segment with respect to this specific obligation. Values: compliant (segment meets all requirements), non_compliant (violations identified), under_review (audit in progress), remediation_in_progress (corrective actions underway), exempt (exemption granted).',
    `segment_id` BIGINT COMMENT 'Foreign key to audience_segment. Part of the natural key.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation that governs this segment',
    `audience_risk_level_id` BIGINT COMMENT 'Assessed risk level specific to this segment-obligation combination. May differ from the obligations general risk_level based on segment characteristics (e.g., a childrens segment under COPPA has critical risk even if COPPAs general risk is high).',
    `activation_date` DATE COMMENT 'Date when this audience segment was activated for use under this specific regulatory obligation. Represents when the segment was first deployed in campaigns subject to this regulation.',
    `audit_findings` STRING COMMENT 'Summary of findings from the most recent compliance audit. Documents any violations, concerns, or confirmations of compliance. Used for audit trail and remediation tracking.',
    `ccpa_opt_out_honored` BOOLEAN COMMENT 'Indicates whether California Consumer Privacy Act (CCPA) opt-out signals are honored when activating this segment for California residents. When True, individuals who have exercised their CCPA right to opt out of sale/sharing of personal information are excluded from segment activation. Required for compliance with CCPA and its amendment CPRA. [Moved from audience_segment: CCPA opt-out handling is a compliance attribute specific to the CCPA regulatory obligation. This should be tracked in the segment-obligation compliance relationship where it can be audited, dated, and linked to the specific CCPA obligation record. The segment itself shouldnt carry obligation-specific compliance flags.]',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was created in the system.',
    `deactivation_date` DATE COMMENT 'Date when this segment was deactivated or removed from use under this obligation. Null if segment remains active. Used to track compliance history.',
    `deactivation_reason` STRING COMMENT 'Reason why the segment was deactivated under this obligation. Examples: compliance violation, obligation no longer applicable, segment retired, business decision. Null if segment is active.',
    `exemption_basis` STRING COMMENT 'Legal or regulatory basis for any exemption granted for this segment under this obligation. Null if no exemption applies. Examples: safe harbor provision, de minimis exception, grandfathered status, regulatory waiver reference.',
    `exemption_expiration_date` DATE COMMENT 'Date when any granted exemption expires and full compliance is required. Null if no exemption or if exemption is permanent.',
    `gdpr_lawful_basis` STRING COMMENT 'The GDPR (General Data Protection Regulation) Article 6 lawful basis under which audience data is processed to build and activate this segment for EU audiences. consent requires explicit opt-in; legitimate_interest requires a balancing test; contract applies to subscriber-based segments; not_applicable for non-EU segments. Required for regulatory compliance reporting. [Moved from audience_segment: GDPR lawful basis is specific to the GDPR regulatory obligation and represents compliance metadata that belongs in the segment-obligation relationship. Different segments may have different lawful bases under GDPR, and this should be tracked as part of the compliance record with audit dates and status, not as a standalone attribute on the segment.]. Valid values are `consent|legitimate_interest|contract|not_applicable`',
    `is_coppa_restricted` BOOLEAN COMMENT 'Indicates whether this segment is subject to COPPA (Childrens Online Privacy Protection Act) restrictions, meaning it includes or may include children under 13. COPPA-restricted segments are prohibited from behavioral targeting and require parental consent mechanisms. Critical compliance flag for ad sales and digital activation workflows. [Moved from audience_segment: This boolean flag indicates COPPA applicability but doesnt capture the compliance relationship details. The segment_regulatory_compliance association should track the actual COPPA obligation (via regulatory_obligation_id) with full audit history, compliance status, and exemption basis. The flag in audience_segment can remain as a derived/cached indicator for quick filtering, but the authoritative compliance relationship lives in the association.]',
    `last_audit_date` DATE COMMENT 'Date when this segment-obligation pairing was last audited for compliance. Used to track audit frequency and schedule next review.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was last modified.',
    `next_audit_date` DATE COMMENT 'Scheduled date for the next compliance audit of this segment under this obligation. Calculated based on obligation compliance_frequency and risk_level.',
    `remediation_due_date` DATE COMMENT 'Deadline by which remediation actions must be completed to avoid penalties or enforcement action. Null if no remediation required.',
    `remediation_plan` STRING COMMENT 'Description of corrective actions planned or in progress to address any compliance gaps. Null if segment is compliant or exempt.',
    `responsible_compliance_officer` STRING COMMENT 'Name or employee ID of the compliance officer accountable for managing this segment-obligation compliance relationship.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_segment_regulatory_compliance PRIMARY KEY(`segment_regulatory_compliance_id`)
) COMMENT 'This association product represents the compliance relationship between audience segments and regulatory obligations. It captures the activation compliance status, audit history, and risk assessment for each segment-obligation pairing. Each record links one audience segment to one regulatory obligation with attributes that track when the segment was activated under that obligation, its current compliance state, audit findings, and any exemptions or special handling requirements.. Existence Justification: In media broadcasting operations, audience segments are subject to multiple regulatory obligations simultaneously (COPPA for childrens content, GDPR for EU audiences, accessibility requirements, advertising restrictions), and each regulatory obligation governs multiple audience segments across the portfolio. The compliance team actively manages these relationships by tracking activation dates, conducting periodic audits, assessing risk levels specific to each segment-obligation pairing, documenting exemptions, and maintaining remediation plans. This is an operational compliance management process, not an analytical correlation. [VENDOR-ANCHOR] Identifier anchors: Nielsen panel/DMA measurement identifiers. System of record: Nielsen.';

