CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`dsp_usage_report` (
    `dsp_usage_report_id` BIGINT COMMENT 'Surrogate primary key for the DSP usage report.',
    `master_recording_id` BIGINT COMMENT 'Recording the usage relates to.',
    `mechanical_royalty_report_id` BIGINT COMMENT 'Related mechanical royalty report.',
    `release_id` BIGINT COMMENT 'FK to the release (album/EP/single) the track belongs to.',
    `rights_territory_id` BIGINT COMMENT 'Territory of consumption.',
    `title_id` BIGINT COMMENT 'FK to the content title associated with the streamed recording.',
    `version_id` BIGINT COMMENT 'FK to the specific content version (master) streamed.',
    `_created_at` TIMESTAMP COMMENT 'Record creation timestamp for lineage.',
    `_source_code` STRING COMMENT 'Natural identifier in the source system.',
    `_updated_at` TIMESTAMP COMMENT 'Record last-update timestamp for lineage.',
    `artist_name` STRING COMMENT 'Performing artist name.',
    `complete_play_count` BIGINT COMMENT 'Number of streams that met the platform completion threshold.',
    `completed_stream_count` BIGINT COMMENT 'Number of qualifying/completed streams (>= 30s) for royalty calculation.',
    `completion_rate` DECIMAL(18,2) COMMENT 'Ratio of completed plays to total plays.',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `created_timestamp` TIMESTAMP COMMENT '',
    `currency_code` STRING COMMENT 'ISO currency code of the reported revenue.',
    `download_count` BIGINT COMMENT 'Number of downloads in the period.',
    `dsp_name` STRING COMMENT 'Digital service provider name (Spotify, Apple Music, YouTube Music, Amazon Music, etc.).',
    `dsp_platform` STRING COMMENT 'Digital service provider: Spotify, Apple Music, YouTube Music, Amazon Music, etc.',
    `dsp_platform_code` STRING COMMENT 'Canonical platform code for the DSP.',
    `estimated_revenue_amount` DECIMAL(18,2) COMMENT '',
    `estimated_royalty_amount` DECIMAL(18,2) COMMENT 'Estimated royalty payable derived from the reported usage.',
    `gross_revenue_amount` DECIMAL(18,2) COMMENT 'Gross streaming revenue attributable to this recording in the period.',
    `ingested_flag` BOOLEAN COMMENT 'Whether the report has been ingested into the analytics platform.',
    `is_final_flag` BOOLEAN COMMENT 'Indicates the report is final (not an interim/estimate restatement).',
    `is_interactive_flag` BOOLEAN COMMENT 'Whether streams were interactive/on-demand vs non-interactive.',
    `is_monetized_flag` BOOLEAN COMMENT 'Whether the streams were monetized (paid/ad-supported) vs free.',
    `is_promotional_flag` BOOLEAN COMMENT 'Whether streams occurred under a promotional/free tier.',
    `isrc` STRING COMMENT 'ISRC code identifying the recording streamed (^[A-Z]{2}[A-Z0-9]{3}[0-9]{7}$).',
    `iswc` STRING COMMENT 'ISWC of the underlying composition. ^T-d{9}-d$',
    `listener_count` BIGINT COMMENT 'Distinct listeners in the period.',
    `monetization_model` STRING COMMENT 'Ad-supported (free) vs premium (paid) tier of the stream.',
    `monetized_flag` BOOLEAN COMMENT 'Whether streams were monetized.',
    `monetized_stream_count` BIGINT COMMENT 'Streams eligible for royalty monetization.',
    `net_revenue` DECIMAL(18,2) COMMENT 'Net revenue attributed to the recording.',
    `net_revenue_amount` DECIMAL(18,2) COMMENT 'Net revenue attributed to the streams in the period.',
    `per_stream_rate` DECIMAL(18,2) COMMENT 'Effective per-stream payout rate.',
    `playlist_add_count` STRING COMMENT '',
    `report_created_at` TIMESTAMP COMMENT 'Timestamp the DSP usage report row was created.',
    `report_received_at` TIMESTAMP COMMENT 'Timestamp the DSP usage report was received.',
    `report_received_date` DATE COMMENT 'Date the DSP usage report was received.',
    `report_source_file` STRING COMMENT 'Source file/feed reference for the ingested DSP report.',
    `report_updated_at` TIMESTAMP COMMENT 'Timestamp the DSP usage report row was last updated.',
    `reporting_period_end` DATE COMMENT 'End of the reporting period.',
    `reporting_period_end_date` DATE COMMENT 'End date of the streaming reporting period.',
    `reporting_period_start` DATE COMMENT 'Start of the reporting period.',
    `reporting_period_start_date` DATE COMMENT 'Start date of the streaming reporting period.',
    `revenue_amount` DECIMAL(18,2) COMMENT 'Reported revenue attributable to usage.',
    `royalty_currency_code` STRING COMMENT 'ISO 4217 currency code for the estimated royalty amount.',
    `save_count` BIGINT COMMENT 'Number of times the track was saved/added to a library or playlist.',
    `skip_count` BIGINT COMMENT 'Number of streams skipped before completion threshold.',
    `skip_rate` DECIMAL(18,2) COMMENT '',
    `source_code` STRING COMMENT 'Natural key in the source system.',
    `stream_count` BIGINT COMMENT 'Total number of streams reported for the ISRC in the period.',
    `stream_seconds_total` BIGINT COMMENT 'Total seconds streamed for the recording in the period.',
    `stream_type` STRING COMMENT 'Interactive, non-interactive, or programmatic stream classification.',
    `subscription_tier` STRING COMMENT 'Subscription tier the streams were attributed to (premium, ad-supported, trial).',
    `territory` STRING COMMENT 'Territory of the reported streams.',
    `thirty_second_play_count` BIGINT COMMENT 'Number of plays exceeding 30 seconds for royalty qualification.',
    `total_streaming_seconds` BIGINT COMMENT 'Aggregate listening time in seconds across all streams.',
    `track_title` STRING COMMENT 'Title of the streamed track.',
    `unique_listener_count` BIGINT COMMENT 'Distinct listeners who streamed the recording.',
    `updated_at` TIMESTAMP COMMENT 'Record last-updated timestamp.',
    `updated_timestamp` TIMESTAMP COMMENT '',
    CONSTRAINT pk_dsp_usage_report PRIMARY KEY(`dsp_usage_report_id`)
) COMMENT 'ISRC-keyed streaming counts and revenue from digital service providers (Spotify, Apple Music, YouTube Music) for music catalog audience measurement.';

